{
  "name": "Imposter Reveal",
  "description": "A thrilling social party game where players must find the hidden imposter. Choose from various categories or create your own using AI-powered word generation."
}

export interface Category {
  id: string;
  name: string;
  words: string[];
  isCustom?: boolean;
}

export interface Player {
  id: number;
  name: string;
  word: string;
  isImposter: boolean;
  hasSeenWord: boolean;
}

export enum GameState {
  SETUP = 'SETUP',
  PRE_REVEAL = 'PRE_REVEAL',
  REVEALING = 'REVEALING',
  DISCUSSION = 'DISCUSSION'
}

import { Category } from './types';

export const DEFAULT_CATEGORIES: Category[] = [
  {
    id: '1',
    name: 'Animals',
    words: ['Lion', 'Elephant', 'Penguin', 'Giraffe', 'Kangaroo', 'Dolphin', 'Tiger', 'Panda', 'Eagle', 'Shark']
  },
  {
    id: '2',
    name: 'Food',
    words: ['Pizza', 'Sushi', 'Burger', 'Taco', 'Pasta', 'Ice Cream', 'Pancake', 'Steak', 'Salad', 'Ramen']
  },
  {
    id: '3',
    name: 'Places',
    words: ['Eiffel Tower', 'Grand Canyon', 'Tokyo', 'Pyramids of Giza', 'London', 'Great Wall of China', 'New York City', 'Colosseum']
  },
  {
    id: '4',
    name: 'Movies',
    words: ['Star Wars', 'The Godfather', 'Avengers', 'Inception', 'Toy Story', 'The Matrix', 'Jurassic Park', 'Spider-Man']
  }
];

export const MIN_PLAYERS = 3;
export const MAX_PLAYERS = 8;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateWordsForCategory(topic: string): Promise<string[]> {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a list of 15 unique, well-known items or names related to the topic: "${topic}". The items should be simple enough for a word guessing game.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          words: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of words related to the topic."
          }
        },
        required: ["words"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return data.words;
  } catch (error) {
    console.error("Failed to parse AI response:", error);
    return [];
  }
}

import React, { useState, useCallback, useEffect } from 'react';
import { GameState, Player, Category } from './types';
import { DEFAULT_CATEGORIES, MIN_PLAYERS, MAX_PLAYERS } from './constants';
import { generateWordsForCategory } from './services/geminiService';

// Sub-components defined within App.tsx to keep it concise but organized
const Header = () => (
  <header className="py-8 text-center">
    <h1 className="text-5xl font-extrabold tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-red-500 to-orange-400">
      IMPOSTER
    </h1>
    <p className="text-slate-400 mt-2 uppercase tracking-widest text-xs font-semibold">Find the one who doesn't belong</p>
  </header>
);

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.SETUP);
  const [playerCount, setPlayerCount] = useState<number>(4);
  const [categories, setCategories] = useState<Category[]>(DEFAULT_CATEGORIES);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string>(DEFAULT_CATEGORIES[0].id);
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState<number>(0);
  const [isWordVisible, setIsWordVisible] = useState<boolean>(false);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);
  const [customTopic, setCustomTopic] = useState<string>('');

  // Handle game start logic
  const startGame = useCallback(() => {
    const category = categories.find(c => c.id === selectedCategoryId) || categories[0];
    const secretWord = category.words[Math.floor(Math.random() * category.words.length)];
    const imposterIndex = Math.floor(Math.random() * playerCount);

    const newPlayers: Player[] = Array.from({ length: playerCount }, (_, i) => ({
      id: i + 1,
      name: `Player ${i + 1}`,
      word: i === imposterIndex ? 'YOU ARE THE IMPOSTER' : secretWord,
      isImposter: i === imposterIndex,
      hasSeenWord: false
    }));

    setPlayers(newPlayers);
    setCurrentPlayerIndex(0);
    setGameState(GameState.PRE_REVEAL);
    setIsWordVisible(false);
  }, [playerCount, selectedCategoryId, categories]);

  // Handle custom category generation
  const handleAddCustomCategory = async () => {
    if (!customTopic.trim()) return;
    setIsGenerating(true);
    try {
      const words = await generateWordsForCategory(customTopic);
      if (words.length > 0) {
        const newCategory: Category = {
          id: Date.now().toString(),
          name: customTopic,
          words,
          isCustom: true
        };
        setCategories(prev => [...prev, newCategory]);
        setSelectedCategoryId(newCategory.id);
        setCustomTopic('');
      }
    } catch (err) {
      alert("Failed to generate words. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNextPlayer = () => {
    if (currentPlayerIndex < playerCount - 1) {
      setCurrentPlayerIndex(prev => prev + 1);
      setGameState(GameState.PRE_REVEAL);
      setIsWordVisible(false);
    } else {
      setGameState(GameState.DISCUSSION);
    }
  };

  const renderSetup = () => (
    <div className="max-w-md mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl">
        <label className="block text-sm font-medium text-slate-300 mb-4">Number of Players</label>
        <div className="flex items-center justify-between gap-4">
          <button 
            onClick={() => setPlayerCount(Math.max(MIN_PLAYERS, playerCount - 1))}
            className="w-12 h-12 rounded-xl bg-slate-700 hover:bg-slate-600 flex items-center justify-center transition-colors text-2xl font-bold"
          >-</button>
          <span className="text-4xl font-black text-white">{playerCount}</span>
          <button 
            onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))}
            className="w-12 h-12 rounded-xl bg-slate-700 hover:bg-slate-600 flex items-center justify-center transition-colors text-2xl font-bold"
          >+</button>
        </div>
      </div>

      <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl">
        <label className="block text-sm font-medium text-slate-300 mb-4">Select Category</label>
        <div className="grid grid-cols-2 gap-3 mb-6">
          {categories.map(cat => (
            <button
              key={cat.id}
              onClick={() => setSelectedCategoryId(cat.id)}
              className={`p-3 rounded-xl border text-sm font-semibold transition-all ${
                selectedCategoryId === cat.id 
                  ? 'bg-orange-500 border-orange-400 text-white shadow-lg shadow-orange-500/20 scale-105' 
                  : 'bg-slate-700 border-slate-600 text-slate-300 hover:bg-slate-600'
              }`}
            >
              {cat.name}
            </button>
          ))}
        </div>

        <div className="relative mt-4">
          <input
            type="text"
            value={customTopic}
            onChange={(e) => setCustomTopic(e.target.value)}
            placeholder="E.g. GTA 5 Characters"
            className="w-full bg-slate-900 border border-slate-600 rounded-xl p-3 pr-24 focus:ring-2 focus:ring-orange-500 outline-none text-slate-100"
          />
          <button
            onClick={handleAddCustomCategory}
            disabled={isGenerating || !customTopic}
            className="absolute right-2 top-1.5 bottom-1.5 px-4 rounded-lg bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-600 text-xs font-bold transition-colors"
          >
            {isGenerating ? '...' : 'ADD AI'}
          </button>
        </div>
      </div>

      <button
        onClick={startGame}
        className="w-full py-4 rounded-2xl bg-gradient-to-r from-red-600 to-orange-600 text-white font-black text-xl hover:from-red-500 hover:to-orange-500 shadow-2xl shadow-orange-600/30 transition-all active:scale-95"
      >
        START GAME
      </button>
    </div>
  );

  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-8 animate-in fade-in zoom-in duration-300">
      <div className="space-y-4">
        <p className="text-slate-400 uppercase tracking-widest text-sm font-bold">Pass the phone to</p>
        <h2 className="text-6xl font-black text-white">{players[currentPlayerIndex].name}</h2>
      </div>

      <div className="p-8 bg-slate-800/30 rounded-full w-48 h-48 mx-auto flex items-center justify-center border-4 border-dashed border-slate-700 animate-pulse">
        <span className="text-4xl">📱</span>
      </div>

      <button
        onClick={() => setGameState(GameState.REVEALING)}
        className="w-full py-6 rounded-2xl bg-indigo-600 text-white font-bold text-2xl shadow-lg hover:bg-indigo-500 transition-all"
      >
        I AM READY
      </button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-8 animate-in fade-in duration-300">
      <div className="space-y-2">
        <h3 className="text-slate-400 font-bold uppercase text-sm tracking-widest">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-300 text-lg">Tap to see your secret word</p>
      </div>

      <div 
        onClick={() => setIsWordVisible(!isWordVisible)}
        className={`relative h-64 rounded-3xl cursor-pointer transition-all duration-500 flex items-center justify-center overflow-hidden border-2 ${
          isWordVisible 
            ? 'bg-slate-100 border-white shadow-[0_0_50px_rgba(255,255,255,0.1)]' 
            : 'bg-slate-800 border-slate-700 hover:bg-slate-700 shadow-2xl'
        }`}
      >
        {isWordVisible ? (
          <div className="text-center p-6 animate-in zoom-in duration-200">
            <span className={`text-4xl font-black ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-900'}`}>
              {players[currentPlayerIndex].word}
            </span>
          </div>
        ) : (
          <div className="text-center">
            <span className="text-6xl filter grayscale opacity-20">🕵️‍♂️</span>
            <p className="mt-4 font-bold text-slate-500">CLICK TO REVEAL</p>
          </div>
        )}
      </div>

      {isWordVisible && (
        <button
          onClick={handleNextPlayer}
          className="w-full py-4 rounded-2xl bg-green-600 text-white font-bold text-xl hover:bg-green-500 animate-in slide-in-from-bottom-2 duration-300"
        >
          OK, I'VE SEEN IT
        </button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-10 animate-in zoom-in duration-500">
      <div className="space-y-4">
        <h2 className="text-4xl font-black text-white">All words revealed!</h2>
        <p className="text-slate-400 text-lg">Discuss and find the imposter among you. Every player takes turns asking one question.</p>
      </div>

      <div className="grid grid-cols-2 gap-4">
        {players.map(p => (
          <div key={p.id} className="p-4 bg-slate-800/50 rounded-xl border border-slate-700 text-slate-300 font-bold">
            {p.name}
          </div>
        ))}
      </div>

      <div className="pt-10 space-y-4">
        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-4 rounded-2xl bg-slate-700 text-white font-bold hover:bg-slate-600 transition-colors"
        >
          NEW GAME
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen p-4 md:p-8">
      <div className="max-w-4xl mx-auto">
        <Header />
        <main className="mt-10">
          {gameState === GameState.SETUP && renderSetup()}
          {gameState === GameState.PRE_REVEAL && renderPreReveal()}
          {gameState === GameState.REVEALING && renderRevealing()}
          {gameState === GameState.DISCUSSION && renderDiscussion()}
        </main>
      </div>

      {/* Background Decor */}
      <div className="fixed top-0 left-0 w-full h-full -z-10 pointer-events-none opacity-20 overflow-hidden">
        <div className="absolute -top-20 -left-20 w-96 h-96 bg-red-600 rounded-full mix-blend-screen filter blur-[120px] animate-pulse"></div>
        <div className="absolute top-1/2 -right-20 w-96 h-96 bg-orange-600 rounded-full mix-blend-screen filter blur-[120px] animate-pulse delay-700"></div>
        <div className="absolute -bottom-20 left-1/2 w-96 h-96 bg-indigo-600 rounded-full mix-blend-screen filter blur-[120px] animate-pulse delay-1000"></div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
