  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-8 animate-in fade-in zoom-in duration-300">
      <div className="space-y-4">
        <p className="text-slate-400 uppercase tracking-widest text-sm font-bold">Pass the phone to</p>
        <h2 className="text-6xl font-black text-white">{players[currentPlayerIndex].name}</h2>
      </div>

      <div className="p-8 bg-slate-800/30 rounded-full w-48 h-48 mx-auto flex items-center justify-center border-4 border-dashed border-slate-700 animate-pulse">
        <span className="text-4xl">📱</span>
      </div>

      <button
        onClick={() => setGameState(GameState.REVEALING)}
        className="w-full py-6 rounded-2xl bg-indigo-600 text-white font-bold text-2xl shadow-lg hover:bg-indigo-500 transition-all"
      >
        I AM READY
      </button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-8 animate-in fade-in duration-300">
      <div className="space-y-2">
        <h3 className="text-slate-400 font-bold uppercase text-sm tracking-widest">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-300 text-lg">Tap to see your secret word</p>
      </div>

      <div 
        onClick={() => setIsWordVisible(!isWordVisible)}
        className={`relative h-64 rounded-3xl cursor-pointer transition-all duration-500 flex items-center justify-center overflow-hidden border-2 ${
          isWordVisible 
            ? 'bg-slate-100 border-white shadow-[0_0_50px_rgba(255,255,255,0.1)]' 
            : 'bg-slate-800 border-slate-700 hover:bg-slate-700 shadow-2xl'
        }`}
      >
        {isWordVisible ? (
          <div className="text-center p-6 animate-in zoom-in duration-200">
            <span className={`text-4xl font-black ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-900'}`}>
              {players[currentPlayerIndex].word}
            </span>
          </div>
        ) : (
          <div className="text-center">
            <span className="text-6xl filter grayscale opacity-20">🕵️‍♂️</span>
            <p className="mt-4 font-bold text-slate-500">CLICK TO REVEAL</p>
          </div>
        )}
      </div>

      {isWordVisible && (
        <button
          onClick={handleNextPlayer}
          className="w-full py-4 rounded-2xl bg-green-600 text-white font-bold text-xl hover:bg-green-500 animate-in slide-in-from-bottom-2 duration-300"
        >
          OK, I'VE SEEN IT
        </button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-10 animate-in zoom-in duration-500">
      <div className="space-y-4">
        <h2 className="text-4xl font-black text-white">All words revealed!</h2>
        <p className="text-slate-400 text-lg">Discuss and find the imposter among you. Every player takes turns asking one question.</p>
      </div>

      <div className="grid grid-cols-2 gap-4">
        {players.map(p => (
          <div key={p.id} className="p-4 bg-slate-800/50 rounded-xl border border-slate-700 text-slate-300 font-bold">
            {p.name}
          </div>
        ))}
      </div>

      <div className="pt-10 space-y-4">
        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-4 rounded-2xl bg-slate-700 text-white font-bold hover:bg-slate-600 transition-colors"
        >
          NEW GAME
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen p-4 md:p-8">
      <div className="max-w-4xl mx-auto">
        <Header />
