import { generateWordsForCategory } from './services/geminiService';

const Header = () => (
  <header className="py-8 text-center">
    <h1 className="text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 via-orange-500 to-yellow-500 drop-shadow-sm">
