  const [gameState, setGameState] = useState<GameState>(GameState.SETUP);
  const [playerCount, setPlayerCount] = useState<number>(4);
  const [categories, setCategories] = useState<Category[]>(DEFAULT_CATEGORIES);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>(['games']);
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState<number>(0);
  const [isWordVisible, setIsWordVisible] = useState<boolean>(false);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);
  const [customTopic, setCustomTopic] = useState<string>('');

  const startGame = useCallback(() => {
    if (selectedCategoryIds.length === 0) {
      alert("Please select at least one category!");
      return;
    }

    const selectedCats = categories.filter(c => selectedCategoryIds.includes(c.id));
    const allWords = selectedCats.flatMap(c => c.words);

    if (allWords.length === 0) {
      alert("No words found in selected categories.");
      return;
    }

    const secretWord = allWords[Math.floor(Math.random() * allWords.length)];
    const imposterIndex = Math.floor(Math.random() * playerCount);

    const newPlayers: Player[] = Array.from({ length: playerCount }, (_, i) => ({
      id: i + 1,
      name: `Player ${i + 1}`,
      word: i === imposterIndex ? 'YOU ARE THE IMPOSTER' : secretWord,
      isImposter: i === imposterIndex,
      hasSeenWord: false
    }));

    setPlayers(newPlayers);
    setCurrentPlayerIndex(0);
    setGameState(GameState.PRE_REVEAL);
    setIsWordVisible(false);
  }, [playerCount, selectedCategoryIds, categories]);

  const toggleCategory = (id: string) => {
    setSelectedCategoryIds(prev => {
      if (prev.includes(id)) {
        if (prev.length === 1) return prev; // Keep at least one
        return prev.filter(cid => cid !== id);
      } else {
        return [...prev, id];
      }
    });
  };

  const handleAddCustomCategory = async () => {
    if (!customTopic.trim()) return;
    setIsGenerating(true);
    try {
      const words = await generateWordsForCategory(customTopic);
      if (words.length > 0) {
        const newCategory: Category = {
          id: Date.now().toString(),
          name: customTopic,
          words,
          isCustom: true
        };
        setCategories(prev => [...prev, newCategory]);
        setSelectedCategoryIds(prev => [...prev, newCategory.id]);
        setCustomTopic('');
      }
    } catch (err) {
      alert("Failed to generate words. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNextPlayer = () => {
    if (currentPlayerIndex < playerCount - 1) {
      setCurrentPlayerIndex(prev => prev + 1);
      setGameState(GameState.PRE_REVEAL);
      setIsWordVisible(false);
    } else {
      setGameState(GameState.DISCUSSION);
    }
  };

  const renderSetup = () => (
    <div className="max-w-md mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
