          >-</button>
          <div className="text-center">
            <span className="text-6xl font-black text-white tabular-nums drop-shadow-lg">{playerCount}</span>
            <p className="text-[10px] font-bold text-slate-500 mt-1 uppercase">Total</p>
          </div>
          <button 
            onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))}
            className="w-14 h-14 rounded-2xl bg-slate-700/50 hover:bg-slate-600 transition-all text-2xl font-black text-white active:scale-90 border border-slate-600/50"
          >+</button>
        </div>
      </div>

      <div className="bg-slate-800/40 p-6 rounded-3xl border border-slate-700/50 backdrop-blur-xl shadow-2xl">
        <div className="flex justify-between items-center mb-6">
