                key={cat.id}
                onClick={() => toggleCategory(cat.id)}
                className={`p-4 rounded-2xl border-2 text-sm font-bold transition-all relative overflow-hidden group ${
                  isSelected 
                    ? 'bg-orange-500/10 border-orange-500 text-white shadow-lg shadow-orange-500/10' 
                    : 'bg-slate-900/50 border-slate-700/50 text-slate-400 hover:border-slate-500'
                }`}
              >
                {cat.name}
                {isSelected && (
                  <div className="absolute top-1.5 right-1.5 bg-orange-500 w-2 h-2 rounded-full ring-4 ring-orange-500/20" />
                )}
              </button>
            );
          })}
        </div>

        <div className="relative mt-4">
          <input
            type="text"
            value={customTopic}
            onChange={(e) => setCustomTopic(e.target.value)}
            placeholder="E.g. GTA 5 Characters"
            className="w-full bg-slate-900/80 border border-slate-700 rounded-2xl p-4 pr-24 focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none text-slate-100 placeholder:text-slate-600 transition-all"
          />
          <button
            onClick={handleAddCustomCategory}
            disabled={isGenerating || !customTopic}
            className="absolute right-2 top-2 bottom-2 px-4 rounded-xl bg-gradient-to-br from-indigo-600 to-violet-700 hover:from-indigo-500 hover:to-violet-600 disabled:opacity-50 text-[10px] font-black text-white transition-all active:scale-95 shadow-lg shadow-indigo-900/20"
          >
            {isGenerating ? '...' : 'ADD AI'}
          </button>
        </div>
      </div>

      <button
        onClick={startGame}
        className="w-full py-5 rounded-3xl bg-gradient-to-r from-red-600 via-orange-600 to-orange-500 text-white font-black text-xl hover:shadow-[0_0_40px_rgba(249,115,22,0.3)] transition-all active:scale-[0.98] border-t border-white/20"
      >
        START MISSION
      </button>
    </div>
