        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-4 rounded-3xl bg-slate-800 text-slate-400 font-black text-sm uppercase tracking-widest hover:bg-slate-700 hover:text-white transition-all border border-slate-700/50"
        >
          ABANDON MISSION (RESET)
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0a0f1d] p-4 md:p-8 selection:bg-orange-500/30">
      <div className="max-w-4xl mx-auto relative z-10">
