          >-</button>
          <div className="text-center">
            <span className="text-7xl font-black text-white tabular-nums drop-shadow-lg scale-110 block">{playerCount}</span>
            <p className="text-[10px] font-bold text-slate-500 mt-2 uppercase tracking-tighter">Players</p>
          </div>
          <button 
            onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >+</button>
        </div>
      </div>

      {/* Category Grid */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-2 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500">Categories</label>
          <button 
            onClick={() => setSelectedCategoryIds(categories.map(c => c.id))}
            className="text-[10px] font-black text-orange-500 hover:text-orange-400 uppercase"
          >
            Toggle All
          </button>
        </div>
        <div className="grid grid-cols-2 gap-3 mb-6">
          {categories.map(cat => {
            const isSelected = selectedCategoryIds.includes(cat.id);
            return (
              <button
                key={cat.id}
                onClick={() => toggleCategory(cat.id)}
                className={`p-4 rounded-2xl border-2 text-sm font-bold transition-all relative overflow-hidden active:scale-95 ${
                  isSelected 
                    ? 'bg-orange-500/10 border-orange-500 text-white shadow-xl shadow-orange-500/10' 
                    : 'bg-slate-900/50 border-slate-800 text-slate-500 hover:border-slate-600'
                }`}
              >
                {cat.name}
              </button>
            );
          })}
        </div>

        {/* Custom Input */}
        <div className="space-y-3 pt-4 border-t border-slate-700/50">
          <input
            type="text"
            value={customTopic}
            onChange={(e) => setCustomTopic(e.target.value)}
            placeholder="Category Name (e.g. Friends)"
            className="w-full bg-slate-900/80 border border-slate-800 rounded-2xl p-4 text-xs font-bold focus:ring-2 focus:ring-orange-500 outline-none text-slate-100 placeholder:text-slate-600"
          />
          <div className="relative">
            <textarea
              value={customWordsInput}
              onChange={(e) => setCustomWordsInput(e.target.value)}
              placeholder="Words, separated, by, commas..."
              className="w-full bg-slate-900/80 border border-slate-800 rounded-2xl p-4 pr-24 text-xs font-medium focus:ring-2 focus:ring-orange-500 outline-none text-slate-100 placeholder:text-slate-600 min-h-[80px] resize-none"
            />
            <button
              onClick={handleAddCustomCategory}
              className="absolute right-2 bottom-2 px-4 py-2 rounded-xl bg-orange-600 hover:bg-orange-500 text-[10px] font-black text-white transition-all active:scale-95 shadow-lg"
            >
              ADD CUSTOM
            </button>
          </div>
        </div>
      </div>

      {/* Chaos Mode Toggle */}
      <div 
        className={`animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-3 p-6 rounded-3xl border transition-all duration-500 backdrop-blur-xl flex items-center justify-between group cursor-pointer shadow-xl ${
          isChaosMode ? 'bg-red-950/20 border-red-500/50 shadow-red-500/20' : 'bg-slate-800/40 border-slate-700/50'
        }`}
        onClick={() => setIsChaosMode(!isChaosMode)}
      >
        <div className="flex-1">
          <div className="flex items-center gap-2">
            <span className={`text-[10px] font-black uppercase tracking-widest ${isChaosMode ? 'text-red-400' : 'text-slate-500'}`}>Chaos Mode</span>
            {isChaosMode && <span className="animate-pulse w-2 h-2 bg-red-500 rounded-full"></span>}
          </div>
          <p className="text-[9px] text-slate-600 font-bold mt-1 uppercase tracking-tighter">Extreme outcomes (2% chance)</p>
        </div>
        <div className={`w-14 h-8 rounded-full transition-all duration-300 relative border ${isChaosMode ? 'bg-red-600 border-red-400' : 'bg-slate-900 border-slate-700'}`}>
          <div className={`absolute top-1 bottom-1 w-6 rounded-full transition-all duration-300 ${isChaosMode ? 'right-1 bg-white' : 'left-1 bg-slate-600'}`} />
        </div>
      </div>

      <button
        onClick={startGame}
        className="animate-in slide-in-from-bottom-12 fade-in duration-1000 stagger-4 w-full py-6 rounded-[2rem] bg-gradient-to-r from-red-600 via-orange-600 to-orange-500 text-white font-black text-2xl hover:scale-[1.02] transition-all active:scale-95 shadow-2xl shadow-orange-900/40 border-t border-white/20"
      >
        START GAME
      </button>
    </div>
  );

  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-500 mt-10">
      <div className="space-y-4">
        <p className="text-slate-500 uppercase tracking-[0.3em] text-[10px] font-black">Pass the phone to</p>
        <h2 className="text-7xl font-black text-white tracking-tighter drop-shadow-2xl">{players[currentPlayerIndex].name}</h2>
      </div>
      <div className="relative flex items-center justify-center py-10">
        <div className="absolute inset-0 bg-orange-500/10 blur-[120px] rounded-full"></div>
        <div className="relative p-14 bg-slate-800/40 rounded-full border-2 border-dashed border-slate-700/50">
          <span className="text-8xl block animate-bounce">📱</span>
        </div>
      </div>
      <button
        onClick={() => setGameState(GameState.REVEALING)}
        className="w-full py-7 rounded-[2rem] bg-white text-slate-950 font-black text-2xl shadow-2xl transition-all active:scale-95 hover:bg-slate-100"
      >
        I AM READY
      </button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-10 animate-in fade-in duration-300 mt-10">
      <div className="space-y-2">
        <h3 className="text-orange-500 font-black uppercase text-[10px] tracking-[0.4em]">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Tap to reveal identity</p>
      </div>
      <div 
        onClick={() => setIsWordVisible(!isWordVisible)}
        className={`relative h-[24rem] rounded-[3rem] cursor-pointer transition-all duration-700 flex items-center justify-center overflow-hidden border-2 ${
          isWordVisible 
            ? 'bg-white border-white' 
            : 'bg-slate-900 border-slate-800 hover:border-slate-700 shadow-2xl'
        }`}
      >
        {isWordVisible ? (
          <div className="text-center p-10 animate-in zoom-in-90 duration-300">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-400 mb-6 opacity-60">Secret Assignment</p>
            <span className={`text-5xl font-black tracking-tight leading-tight ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-950'}`}>
              {players[currentPlayerIndex].word}
            </span>
          </div>
        ) : (
          <div className="text-center group p-10">
            <div className="text-9xl mb-8 opacity-20 filter grayscale">🕵️</div>
            <p className="font-black text-slate-600 tracking-[0.2em] text-xs uppercase">Hold to reveal</p>
          </div>
        )}
      </div>
      {isWordVisible && (
        <button
          onClick={() => {
            if (currentPlayerIndex < playerCount - 1) {
              setCurrentPlayerIndex(prev => prev + 1);
              setGameState(GameState.PRE_REVEAL);
              setIsWordVisible(false);
            } else {
              setGameState(GameState.DISCUSSION);
            }
          }}
          className="w-full py-6 rounded-[2rem] bg-orange-600 text-white font-black text-xl shadow-xl transition-all active:scale-95 animate-in slide-in-from-bottom-8 duration-500"
        >
          I'VE SEEN IT
        </button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-1000 mt-10">
      <div className="space-y-4">
        <div className="inline-block px-4 py-1.5 rounded-full bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-black tracking-[0.3em] uppercase mb-4">Live Mission</div>
        <h2 className="text-6xl font-black text-white tracking-tighter leading-none">DISCUSSION</h2>
        <p className="text-slate-500 text-xs leading-relaxed font-bold uppercase tracking-wide px-6">
          Find the spy before they figure out the secret word.
        </p>
      </div>
      <div className="grid grid-cols-2 gap-4">
        {players.map(p => (
          <div key={p.id} className="p-5 bg-slate-900/60 rounded-[1.5rem] border border-slate-800/80 text-slate-400 font-black transition-all hover:bg-slate-800">
            <span className="text-[9px] block opacity-40 uppercase mb-1">Agent {p.id}</span>
            {p.name}
          </div>
        ))}
      </div>
      <div className="pt-10">
        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-5 rounded-[2rem] bg-slate-800/50 text-slate-400 font-black text-xs uppercase tracking-[0.3em] hover:bg-slate-800 hover:text-white transition-all border border-slate-700/50"
        >
          FINISH GAME
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen relative selection:bg-orange-500/30 overflow-hidden pb-10">
      <div className="max-w-4xl mx-auto relative z-20 px-4">
        <Header />
        <main>
          {gameState === GameState.SETUP && renderSetup()}
          {gameState === GameState.PRE_REVEAL && renderPreReveal()}
          {gameState === GameState.REVEALING && renderRevealing()}
          {gameState === GameState.DISCUSSION && renderDiscussion()}
        </main>
      </div>

      {/* Dynamic Background */}
      <div className="fixed inset-0 -z-10 pointer-events-none overflow-hidden">
        <div className="absolute -top-40 -left-40 w-[600px] h-[600px] bg-red-600/10 rounded-full blur-[120px] animate-float stagger-1"></div>
        <div className="absolute top-1/2 -right-40 w-[700px] h-[700px] bg-orange-600/10 rounded-full blur-[150px] animate-float stagger-2"></div>
        <div className="absolute -bottom-40 left-1/2 w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-[100px] animate-float stagger-3"></div>
        <div className="absolute inset-0 opacity-[0.02]" style={{backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)', backgroundSize: '32px 32px'}}></div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect } from 'react';
import { GameState, Player, Category } from './types';
import { DEFAULT_CATEGORIES, MIN_PLAYERS, MAX_PLAYERS } from './constants';

const Header = () => (
  <header className="py-12 text-center animate-in fade-in zoom-in duration-1000">
    <div className="inline-block relative">
      <h1 className="text-7xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 via-orange-500 to-yellow-500 drop-shadow-2xl">
        IMPOSTER
      </h1>
      <div className="absolute -inset-1 bg-gradient-to-r from-red-500 to-orange-500 rounded-lg blur opacity-20 animate-pulse"></div>
    </div>
    <p className="text-slate-500 mt-4 uppercase tracking-[0.4em] text-[10px] font-extrabold opacity-80 animate-in fade-in slide-in-from-top-2 duration-700 delay-300">
      Trust No One • Find The Spy
    </p>
  </header>
);

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.SETUP);
  const [playerCount, setPlayerCount] = useState<number>(4);
  const [categories, setCategories] = useState<Category[]>(DEFAULT_CATEGORIES);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>(['games']);
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState<number>(0);
  const [isWordVisible, setIsWordVisible] = useState<boolean>(false);
  const [customWordsInput, setCustomWordsInput] = useState<string>('');
  const [isChaosMode, setIsChaosMode] = useState<boolean>(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const installApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setDeferredPrompt(null);
  };

  const startGame = useCallback(() => {
    if (selectedCategoryIds.length === 0) {
      alert("Select at least one category!");
      return;
    }

    const selectedCats = categories.filter(c => selectedCategoryIds.includes(c.id));
    const allWords = selectedCats.flatMap(c => c.words);

    if (allWords.length === 0) {
      alert("No words available in selection.");
      return;
    }

    const secretWord = allWords[Math.floor(Math.random() * allWords.length)];
    let imposterIndices: number[] = [];

    if (isChaosMode && Math.random() < 0.02) {
      const chaosType = Math.random() < 0.5 ? 'ALL' : 'NONE';
      imposterIndices = chaosType === 'ALL' 
        ? Array.from({ length: playerCount }, (_, i) => i) 
        : [];
    } else {
      imposterIndices = [Math.floor(Math.random() * playerCount)];
    }

    const newPlayers: Player[] = Array.from({ length: playerCount }, (_, i) => ({
      id: i + 1,
      name: `Player ${i + 1}`,
      word: imposterIndices.includes(i) ? 'YOU ARE THE IMPOSTER' : secretWord,
      isImposter: imposterIndices.includes(i),
      hasSeenWord: false
    }));

    setPlayers(newPlayers);
    setCurrentPlayerIndex(0);
    setGameState(GameState.PRE_REVEAL);
    setIsWordVisible(false);
  }, [playerCount, selectedCategoryIds, categories, isChaosMode]);

  const toggleCategory = (id: string) => {
    setSelectedCategoryIds(prev => {
      if (prev.includes(id)) {
        if (prev.length === 1) return prev;
        return prev.filter(cid => cid !== id);
      }
      return [...prev, id];
    });
  };

  const handleAddCustomWords = () => {
    const newWords = customWordsInput.split(',')
      .map(s => s.trim())
      .filter(s => s.length > 0);

    if (newWords.length === 0) {
      alert("Enter some words separated by commas!");
      return;
    }

    setCategories(prev => {
      const customIdx = prev.findIndex(c => c.id === 'custom_words_added');
      if (customIdx > -1) {
        const updated = [...prev];
        updated[customIdx] = {
          ...updated[customIdx],
          words: [...new Set([...updated[customIdx].words, ...newWords])]
        };
        return updated;
      } else {
        const newCat: Category = {
          id: 'custom_words_added',
          name: 'Custom',
          words: newWords,
          isCustom: true
        };
        return [...prev, newCat];
      }
    });

    setSelectedCategoryIds(prev => {
      if (!prev.includes('custom_words_added')) {
        return [...prev, 'custom_words_added'];
      }
      return prev;
    });

    setCustomWordsInput('');
  };

  const renderSetup = () => (
    <div className="max-w-md mx-auto space-y-6 pb-20 px-2">
      {/* Install Prompt */}
      {deferredPrompt && (
        <div className="animate-in slide-in-from-top-4 fade-in duration-1000 stagger-1 bg-gradient-to-r from-indigo-600/20 to-violet-600/20 p-4 rounded-2xl border border-indigo-500/30 flex items-center justify-between mb-2 backdrop-blur-md">
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase text-indigo-400">PWA Available</span>
            <span className="text-xs text-slate-300">Install for a better experience</span>
          </div>
          <button 
            onClick={installApp}
            className="px-4 py-1.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-[10px] font-black text-white shadow-lg transition-transform active:scale-95"
          >
            INSTALL
          </button>
        </div>
      )}

      {/* Player Selection */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-1 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl group hover:border-orange-500/30 transition-colors">
        <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6 text-center">Operation Size</label>
        <div className="flex items-center justify-between px-4">
          <button 
            onClick={() => setPlayerCount(Math.max(MIN_PLAYERS, playerCount - 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >-</button>
          <div className="text-center">
            <span className="text-7xl font-black text-white tabular-nums drop-shadow-lg scale-110 block">{playerCount}</span>
            <p className="text-[10px] font-bold text-slate-500 mt-2 uppercase tracking-tighter">Players</p>
          </div>
          <button 
            onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >+</button>
        </div>
      </div>

      {/* Category Grid */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-2 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500">Categories</label>
          <button 
            onClick={() => setSelectedCategoryIds(categories.map(c => c.id))}
            className="text-[10px] font-black text-orange-500 hover:text-orange-400 uppercase"
          >
            Toggle All
          </button>
        </div>
        <div className="grid grid-cols-2 gap-3 mb-6">
          {categories.map(cat => {
            const isSelected = selectedCategoryIds.includes(cat.id);
            return (
              <button
                key={cat.id}
                onClick={() => toggleCategory(cat.id)}
                className={`p-4 rounded-2xl border-2 text-sm font-bold transition-all relative overflow-hidden active:scale-95 ${
                  isSelected 
                    ? 'bg-orange-500/10 border-orange-500 text-white shadow-xl shadow-orange-500/10' 
                    : 'bg-slate-900/50 border-slate-800 text-slate-500 hover:border-slate-600'
                }`}
              >
                {cat.name}
                {cat.id === 'custom_words_added' && (
                  <span className="ml-1 text-[8px] opacity-60">({cat.words.length})</span>
                )}
              </button>
            );
          })}
        </div>

        {/* Custom Input */}
        <div className="space-y-3 pt-4 border-t border-slate-700/50">
          <p className="text-[9px] font-black uppercase tracking-widest text-slate-600 mb-1">Add Custom Words</p>
          <div className="relative">
            <textarea
              value={customWordsInput}
              onChange={(e) => setCustomWordsInput(e.target.value)}
              placeholder="Words, separated, by, commas..."
              className="w-full bg-slate-900/80 border border-slate-800 rounded-2xl p-4 pr-24 text-xs font-medium focus:ring-2 focus:ring-orange-500 outline-none text-slate-100 placeholder:text-slate-600 min-h-[80px] resize-none"
            />
            <button
              onClick={handleAddCustomWords}
              className="absolute right-2 bottom-2 px-4 py-2 rounded-xl bg-orange-600 hover:bg-orange-500 text-[10px] font-black text-white transition-all active:scale-95 shadow-lg"
            >
              ADD WORDS
            </button>
          </div>
        </div>
      </div>

      {/* Chaos Mode Toggle */}
      <div 
        className={`animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-3 p-6 rounded-3xl border transition-all duration-500 backdrop-blur-xl flex items-center justify-between group cursor-pointer shadow-xl ${
          isChaosMode ? 'bg-red-950/20 border-red-500/50 shadow-red-500/20' : 'bg-slate-800/40 border-slate-700/50'
        }`}
        onClick={() => setIsChaosMode(!isChaosMode)}
      >
        <div className="flex-1">
          <div className="flex items-center gap-2">
            <span className={`text-[10px] font-black uppercase tracking-widest ${isChaosMode ? 'text-red-400' : 'text-slate-500'}`}>Chaos Mode</span>
            {isChaosMode && <span className="animate-pulse w-2 h-2 bg-red-500 rounded-full"></span>}
          </div>
          <p className="text-[9px] text-slate-600 font-bold mt-1 uppercase tracking-tighter">Extreme outcomes (2% chance)</p>
        </div>
        <div className={`w-14 h-8 rounded-full transition-all duration-300 relative border ${isChaosMode ? 'bg-red-600 border-red-400' : 'bg-slate-900 border-slate-700'}`}>
          <div className={`absolute top-1 bottom-1 w-6 rounded-full transition-all duration-300 ${isChaosMode ? 'right-1 bg-white' : 'left-1 bg-slate-600'}`} />
        </div>
      </div>

      <button
        onClick={startGame}
        className="animate-in slide-in-from-bottom-12 fade-in duration-1000 stagger-4 w-full py-6 rounded-[2rem] bg-gradient-to-r from-red-600 via-orange-600 to-orange-500 text-white font-black text-2xl hover:scale-[1.02] transition-all active:scale-95 shadow-2xl shadow-orange-900/40 border-t border-white/20"
      >
        START GAME
      </button>
    </div>
  );

  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-500 mt-10">
      <div className="space-y-4">
        <p className="text-slate-500 uppercase tracking-[0.3em] text-[10px] font-black">Pass the phone to</p>
        <h2 className="text-7xl font-black text-white tracking-tighter drop-shadow-2xl">{players[currentPlayerIndex].name}</h2>
      </div>
      <div className="relative flex items-center justify-center py-10">
        <div className="absolute inset-0 bg-orange-500/10 blur-[120px] rounded-full"></div>
        <div className="relative p-14 bg-slate-800/40 rounded-full border-2 border-dashed border-slate-700/50">
          <span className="text-8xl block animate-bounce">📱</span>
        </div>
      </div>
      <button
        onClick={() => setGameState(GameState.REVEALING)}
        className="w-full py-7 rounded-[2rem] bg-white text-slate-950 font-black text-2xl shadow-2xl transition-all active:scale-95 hover:bg-slate-100"
      >
        I AM READY
      </button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-10 animate-in fade-in duration-300 mt-10">
      <div className="space-y-2">
        <h3 className="text-orange-500 font-black uppercase text-[10px] tracking-[0.4em]">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Tap to reveal identity</p>
      </div>
      <div 
        onClick={() => setIsWordVisible(!isWordVisible)}
        className={`relative h-[24rem] rounded-[3rem] cursor-pointer transition-all duration-700 flex items-center justify-center overflow-hidden border-2 ${
          isWordVisible 
            ? 'bg-white border-white' 
            : 'bg-slate-900 border-slate-800 hover:border-slate-700 shadow-2xl'
        }`}
      >
        {isWordVisible ? (
          <div className="text-center p-10 animate-in zoom-in-90 duration-300">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-400 mb-6 opacity-60">Secret Assignment</p>
            <span className={`text-5xl font-black tracking-tight leading-tight ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-950'}`}>
              {players[currentPlayerIndex].word}
            </span>
          </div>
        ) : (
          <div className="text-center group p-10">
            <div className="text-9xl mb-8 opacity-20 filter grayscale">🕵️</div>
            <p className="font-black text-slate-600 tracking-[0.2em] text-xs uppercase">Hold to reveal</p>
          </div>
        )}
      </div>
      {isWordVisible && (
        <button
          onClick={() => {
            if (currentPlayerIndex < playerCount - 1) {
              setCurrentPlayerIndex(prev => prev + 1);
              setGameState(GameState.PRE_REVEAL);
              setIsWordVisible(false);
            } else {
              setGameState(GameState.DISCUSSION);
            }
          }}
          className="w-full py-6 rounded-[2rem] bg-orange-600 text-white font-black text-xl shadow-xl transition-all active:scale-95 animate-in slide-in-from-bottom-8 duration-500"
        >
          I'VE SEEN IT
        </button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-1000 mt-10">
      <div className="space-y-4">
        <div className="inline-block px-4 py-1.5 rounded-full bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-black tracking-[0.3em] uppercase mb-4">Live Mission</div>
        <h2 className="text-6xl font-black text-white tracking-tighter leading-none">DISCUSSION</h2>
        <p className="text-slate-500 text-xs leading-relaxed font-bold uppercase tracking-wide px-6">
          Find the spy before they figure out the secret word.
        </p>
      </div>
      <div className="grid grid-cols-2 gap-4">
        {players.map(p => (
          <div key={p.id} className="p-5 bg-slate-900/60 rounded-[1.5rem] border border-slate-800/80 text-slate-400 font-black transition-all hover:bg-slate-800">
            <span className="text-[9px] block opacity-40 uppercase mb-1">Agent {p.id}</span>
            {p.name}
          </div>
        ))}
      </div>
      <div className="pt-10">
        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-5 rounded-[2rem] bg-slate-800/50 text-slate-400 font-black text-xs uppercase tracking-[0.3em] hover:bg-slate-800 hover:text-white transition-all border border-slate-700/50"
        >
          FINISH GAME
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen relative selection:bg-orange-500/30 overflow-hidden pb-10">
      <div className="max-w-4xl mx-auto relative z-20 px-4">
        <Header />
        <main>
          {gameState === GameState.SETUP && renderSetup()}
          {gameState === GameState.PRE_REVEAL && renderPreReveal()}
          {gameState === GameState.REVEALING && renderRevealing()}
          {gameState === GameState.DISCUSSION && renderDiscussion()}
        </main>
      </div>

      {/* Dynamic Background */}
      <div className="fixed inset-0 -z-10 pointer-events-none overflow-hidden">
        <div className="absolute -top-40 -left-40 w-[600px] h-[600px] bg-red-600/10 rounded-full blur-[120px] animate-float stagger-1"></div>
        <div className="absolute top-1/2 -right-40 w-[700px] h-[700px] bg-orange-600/10 rounded-full blur-[150px] animate-float stagger-2"></div>
        <div className="absolute -bottom-40 left-1/2 w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-[100px] animate-float stagger-3"></div>
        <div className="absolute inset-0 opacity-[0.02]" style={{backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)', backgroundSize: '32px 32px'}}></div>
      </div>
    </div>
  );
};

export default App;

export interface Category {
  id: string;
  name: string;
  words: string[];
  isCustom?: boolean;
}

export interface Player {
  id: number;
  name: string;
  word: string;
  isImposter: boolean;
  hasSeenWord: boolean;
}

export enum GameState {
  SETUP = 'SETUP',
  PRE_REVEAL = 'PRE_REVEAL',
  REVEALING = 'REVEALING',
  DISCUSSION = 'DISCUSSION',
  MANAGE_CUSTOM = 'MANAGE_CUSTOM'
}

import React, { useState, useCallback, useEffect } from 'react';
import { GameState, Player, Category } from './types';
import { DEFAULT_CATEGORIES, MIN_PLAYERS, MAX_PLAYERS } from './constants';

const Header = () => (
  <header className="py-12 text-center animate-in fade-in zoom-in duration-1000">
    <div className="inline-block relative">
      <h1 className="text-7xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 via-orange-500 to-yellow-500 drop-shadow-2xl">
        IMPOSTER
      </h1>
      <div className="absolute -inset-1 bg-gradient-to-r from-red-500 to-orange-500 rounded-lg blur opacity-20 animate-pulse"></div>
    </div>
    <p className="text-slate-500 mt-4 uppercase tracking-[0.4em] text-[10px] font-extrabold opacity-80 animate-in fade-in slide-in-from-top-2 duration-700 delay-300">
      Trust No One • Find The Spy
    </p>
  </header>
);

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.SETUP);
  const [playerCount, setPlayerCount] = useState<number>(4);
  const [categories, setCategories] = useState<Category[]>(DEFAULT_CATEGORIES);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>(['games']);
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState<number>(0);
  const [isWordVisible, setIsWordVisible] = useState<boolean>(false);
  const [customWordsInput, setCustomWordsInput] = useState<string>('');
  const [isChaosMode, setIsChaosMode] = useState<boolean>(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const installApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setDeferredPrompt(null);
  };

  const startGame = useCallback(() => {
    if (selectedCategoryIds.length === 0) {
      alert("Select at least one category!");
      return;
    }

    const selectedCats = categories.filter(c => selectedCategoryIds.includes(c.id));
    const allWords = selectedCats.flatMap(c => c.words);

    if (allWords.length === 0) {
      alert("No words available in selection.");
      return;
    }

    const secretWord = allWords[Math.floor(Math.random() * allWords.length)];
    let imposterIndices: number[] = [];

    if (isChaosMode && Math.random() < 0.02) {
      const chaosType = Math.random() < 0.5 ? 'ALL' : 'NONE';
      imposterIndices = chaosType === 'ALL' 
        ? Array.from({ length: playerCount }, (_, i) => i) 
        : [];
    } else {
      imposterIndices = [Math.floor(Math.random() * playerCount)];
    }

    const newPlayers: Player[] = Array.from({ length: playerCount }, (_, i) => ({
      id: i + 1,
      name: `Player ${i + 1}`,
      word: imposterIndices.includes(i) ? 'YOU ARE THE IMPOSTER' : secretWord,
      isImposter: imposterIndices.includes(i),
      hasSeenWord: false
    }));

    setPlayers(newPlayers);
    setCurrentPlayerIndex(0);
    setGameState(GameState.PRE_REVEAL);
    setIsWordVisible(false);
  }, [playerCount, selectedCategoryIds, categories, isChaosMode]);

  const toggleCategory = (id: string) => {
    setSelectedCategoryIds(prev => {
      if (prev.includes(id)) {
        if (prev.length === 1) return prev;
        return prev.filter(cid => cid !== id);
      }
      return [...prev, id];
    });
  };

  const handleAddCustomWords = () => {
    const newWords = customWordsInput.split(',')
      .map(s => s.trim())
      .filter(s => s.length > 0);

    if (newWords.length === 0) {
      alert("Enter some words separated by commas!");
      return;
    }

    setCategories(prev => {
      const customIdx = prev.findIndex(c => c.id === 'custom_words_added');
      if (customIdx > -1) {
        const updated = [...prev];
        updated[customIdx] = {
          ...updated[customIdx],
          words: [...new Set([...updated[customIdx].words, ...newWords])]
        };
        return updated;
      } else {
        const newCat: Category = {
          id: 'custom_words_added',
          name: 'Custom',
          words: newWords,
          isCustom: true
        };
        return [...prev, newCat];
      }
    });

    setSelectedCategoryIds(prev => {
      if (!prev.includes('custom_words_added')) {
        return [...prev, 'custom_words_added'];
      }
      return prev;
    });

    setCustomWordsInput('');
  };

  const removeCustomWord = (wordToRemove: string) => {
    setCategories(prev => {
      return prev.map(cat => {
        if (cat.id === 'custom_words_added') {
          return {
            ...cat,
            words: cat.words.filter(w => w !== wordToRemove)
          };
        }
        return cat;
      });
    });
  };

  const renderManageCustom = () => {
    const customCategory = categories.find(c => c.id === 'custom_words_added');
    const words = customCategory?.words || [];

    return (
      <div className="max-w-md mx-auto space-y-6 pb-20 px-2 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center justify-between mb-4">
          <button 
            onClick={() => setGameState(GameState.SETUP)}
            className="text-slate-500 hover:text-white flex items-center gap-2 font-black uppercase text-[10px] tracking-widest transition-colors"
          >
            ← Back
          </button>
          <h2 className="text-white font-black text-xs uppercase tracking-widest">Custom Database</h2>
        </div>

        <div className="bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
          {words.length === 0 ? (
            <div className="py-12 text-center">
              <p className="text-slate-600 text-[10px] font-black uppercase tracking-widest">Database Empty</p>
              <p className="text-slate-500 text-xs mt-2">Add words on the home screen to see them here.</p>
            </div>
          ) : (
            <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
              {words.map((word, idx) => (
                <div 
                  key={`${word}-${idx}`} 
                  className="flex items-center justify-between p-4 bg-slate-900/50 rounded-2xl border border-slate-800/80 group hover:border-red-500/30 transition-all"
                >
                  <span className="text-slate-200 font-bold text-sm tracking-tight">{word}</span>
                  <button 
                    onClick={() => removeCustomWord(word)}
                    className="w-8 h-8 rounded-xl bg-red-900/20 hover:bg-red-600 text-red-500 hover:text-white transition-all flex items-center justify-center active:scale-90"
                  >
                    ×
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="text-center pt-4">
          <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest leading-relaxed">
            These words are saved in your current session.<br/>Deleting them here removes them from play.
          </p>
        </div>
      </div>
    );
  };

  const renderSetup = () => (
    <div className="max-w-md mx-auto space-y-6 pb-20 px-2">
      {/* Install Prompt */}
      {deferredPrompt && (
        <div className="animate-in slide-in-from-top-4 fade-in duration-1000 stagger-1 bg-gradient-to-r from-indigo-600/20 to-violet-600/20 p-4 rounded-2xl border border-indigo-500/30 flex items-center justify-between mb-2 backdrop-blur-md">
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase text-indigo-400">PWA Available</span>
            <span className="text-xs text-slate-300">Install for a better experience</span>
          </div>
          <button 
            onClick={installApp}
            className="px-4 py-1.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-[10px] font-black text-white shadow-lg transition-transform active:scale-95"
          >
            INSTALL
          </button>
        </div>
      )}

      {/* Player Selection */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-1 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl group hover:border-orange-500/30 transition-colors">
        <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6 text-center">Operation Size</label>
        <div className="flex items-center justify-between px-4">
          <button 
            onClick={() => setPlayerCount(Math.max(MIN_PLAYERS, playerCount - 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >-</button>
          <div className="text-center">
            <span className="text-7xl font-black text-white tabular-nums drop-shadow-lg scale-110 block">{playerCount}</span>
            <p className="text-[10px] font-bold text-slate-500 mt-2 uppercase tracking-tighter">Players</p>
          </div>
          <button 
            onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >+</button>
        </div>
      </div>

      {/* Category Grid */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-2 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500">Categories</label>
          <button 
            onClick={() => setSelectedCategoryIds(categories.map(c => c.id))}
            className="text-[10px] font-black text-orange-500 hover:text-orange-400 uppercase"
          >
            Toggle All
          </button>
        </div>
        <div className="grid grid-cols-2 gap-3 mb-6">
          {categories.map(cat => {
            const isSelected = selectedCategoryIds.includes(cat.id);
            return (
              <button
                key={cat.id}
                onClick={() => toggleCategory(cat.id)}
                className={`p-4 rounded-2xl border-2 text-sm font-bold transition-all relative overflow-hidden active:scale-95 ${
                  isSelected 
                    ? 'bg-orange-500/10 border-orange-500 text-white shadow-xl shadow-orange-500/10' 
                    : 'bg-slate-900/50 border-slate-800 text-slate-500 hover:border-slate-600'
                }`}
              >
                {cat.name}
                {cat.id === 'custom_words_added' && (
                  <span className="ml-1 text-[8px] opacity-60">({cat.words.length})</span>
                )}
              </button>
            );
          })}
        </div>

        {/* Custom Input */}
        <div className="space-y-3 pt-4 border-t border-slate-700/50">
          <div className="flex justify-between items-center mb-1">
            <p className="text-[9px] font-black uppercase tracking-widest text-slate-600">Add Custom Words</p>
            <button 
              onClick={() => setGameState(GameState.MANAGE_CUSTOM)}
              className="text-[9px] font-black uppercase tracking-widest text-orange-500 hover:underline"
            >
              Manage Database →
            </button>
          </div>
          <div className="relative">
            <textarea
              value={customWordsInput}
              onChange={(e) => setCustomWordsInput(e.target.value)}
              placeholder="Words, separated, by, commas..."
              className="w-full bg-slate-900/80 border border-slate-800 rounded-2xl p-4 pr-24 text-xs font-medium focus:ring-2 focus:ring-orange-500 outline-none text-slate-100 placeholder:text-slate-600 min-h-[80px] resize-none"
            />
            <button
              onClick={handleAddCustomWords}
              className="absolute right-2 bottom-2 px-4 py-2 rounded-xl bg-orange-600 hover:bg-orange-500 text-[10px] font-black text-white transition-all active:scale-95 shadow-lg"
            >
              ADD WORDS
            </button>
          </div>
        </div>
      </div>

      {/* Chaos Mode Toggle */}
      <div 
        className={`animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-3 p-6 rounded-3xl border transition-all duration-500 backdrop-blur-xl flex items-center justify-between group cursor-pointer shadow-xl ${
          isChaosMode ? 'bg-red-950/20 border-red-500/50 shadow-red-500/20' : 'bg-slate-800/40 border-slate-700/50'
        }`}
        onClick={() => setIsChaosMode(!isChaosMode)}
      >
        <div className="flex-1">
          <div className="flex items-center gap-2">
            <span className={`text-[10px] font-black uppercase tracking-widest ${isChaosMode ? 'text-red-400' : 'text-slate-500'}`}>Chaos Mode</span>
            {isChaosMode && <span className="animate-pulse w-2 h-2 bg-red-500 rounded-full"></span>}
          </div>
          <p className="text-[9px] text-slate-600 font-bold mt-1 uppercase tracking-tighter">Extreme outcomes (2% chance)</p>
        </div>
        <div className={`w-14 h-8 rounded-full transition-all duration-300 relative border ${isChaosMode ? 'bg-red-600 border-red-400' : 'bg-slate-900 border-slate-700'}`}>
          <div className={`absolute top-1 bottom-1 w-6 rounded-full transition-all duration-300 ${isChaosMode ? 'right-1 bg-white' : 'left-1 bg-slate-600'}`} />
        </div>
      </div>

      <button
        onClick={startGame}
        className="animate-in slide-in-from-bottom-12 fade-in duration-1000 stagger-4 w-full py-6 rounded-[2rem] bg-gradient-to-r from-red-600 via-orange-600 to-orange-500 text-white font-black text-2xl hover:scale-[1.02] transition-all active:scale-95 shadow-2xl shadow-orange-900/40 border-t border-white/20"
      >
        START GAME
      </button>
    </div>
  );

  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-500 mt-10">
      <div className="space-y-4">
        <p className="text-slate-500 uppercase tracking-[0.3em] text-[10px] font-black">Pass the phone to</p>
        <h2 className="text-7xl font-black text-white tracking-tighter drop-shadow-2xl">{players[currentPlayerIndex].name}</h2>
      </div>
      <div className="relative flex items-center justify-center py-10">
        <div className="absolute inset-0 bg-orange-500/10 blur-[120px] rounded-full"></div>
        <div className="relative p-14 bg-slate-800/40 rounded-full border-2 border-dashed border-slate-700/50">
          <span className="text-8xl block animate-bounce">📱</span>
        </div>
      </div>
      <button
        onClick={() => setGameState(GameState.REVEALING)}
        className="w-full py-7 rounded-[2rem] bg-white text-slate-950 font-black text-2xl shadow-2xl transition-all active:scale-95 hover:bg-slate-100"
      >
        I AM READY
      </button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-10 animate-in fade-in duration-300 mt-10">
      <div className="space-y-2">
        <h3 className="text-orange-500 font-black uppercase text-[10px] tracking-[0.4em]">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Tap to reveal identity</p>
      </div>
      <div 
        onClick={() => setIsWordVisible(!isWordVisible)}
        className={`relative h-[24rem] rounded-[3rem] cursor-pointer transition-all duration-700 flex items-center justify-center overflow-hidden border-2 ${
          isWordVisible 
            ? 'bg-white border-white' 
            : 'bg-slate-900 border-slate-800 hover:border-slate-700 shadow-2xl'
        }`}
      >
        {isWordVisible ? (
          <div className="text-center p-10 animate-in zoom-in-90 duration-300">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-400 mb-6 opacity-60">Secret Assignment</p>
            <span className={`text-5xl font-black tracking-tight leading-tight ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-950'}`}>
              {players[currentPlayerIndex].word}
            </span>
          </div>
        ) : (
          <div className="text-center group p-10">
            <div className="text-9xl mb-8 opacity-20 filter grayscale">🕵️</div>
            <p className="font-black text-slate-600 tracking-[0.2em] text-xs uppercase">Hold to reveal</p>
          </div>
        )}
      </div>
      {isWordVisible && (
        <button
          onClick={() => {
            if (currentPlayerIndex < playerCount - 1) {
              setCurrentPlayerIndex(prev => prev + 1);
              setGameState(GameState.PRE_REVEAL);
              setIsWordVisible(false);
            } else {
              setGameState(GameState.DISCUSSION);
            }
          }}
          className="w-full py-6 rounded-[2rem] bg-orange-600 text-white font-black text-xl shadow-xl transition-all active:scale-95 animate-in slide-in-from-bottom-8 duration-500"
        >
          I'VE SEEN IT
        </button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-1000 mt-10">
      <div className="space-y-4">
        <div className="inline-block px-4 py-1.5 rounded-full bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-black tracking-[0.3em] uppercase mb-4">Live Mission</div>
        <h2 className="text-6xl font-black text-white tracking-tighter leading-none">DISCUSSION</h2>
        <p className="text-slate-500 text-xs leading-relaxed font-bold uppercase tracking-wide px-6">
          Find the spy before they figure out the secret word.
        </p>
      </div>
      <div className="grid grid-cols-2 gap-4">
        {players.map(p => (
          <div key={p.id} className="p-5 bg-slate-900/60 rounded-[1.5rem] border border-slate-800/80 text-slate-400 font-black transition-all hover:bg-slate-800">
            <span className="text-[9px] block opacity-40 uppercase mb-1">Agent {p.id}</span>
            {p.name}
          </div>
        ))}
      </div>
      <div className="pt-10">
        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-5 rounded-[2rem] bg-slate-800/50 text-slate-400 font-black text-xs uppercase tracking-[0.3em] hover:bg-slate-800 hover:text-white transition-all border border-slate-700/50"
        >
          FINISH GAME
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen relative selection:bg-orange-500/30 overflow-hidden pb-10">
      <div className="max-w-4xl mx-auto relative z-20 px-4">
        <Header />
        <main>
          {gameState === GameState.SETUP && renderSetup()}
          {gameState === GameState.PRE_REVEAL && renderPreReveal()}
          {gameState === GameState.REVEALING && renderRevealing()}
          {gameState === GameState.DISCUSSION && renderDiscussion()}
          {gameState === GameState.MANAGE_CUSTOM && renderManageCustom()}
        </main>
      </div>

      {/* Dynamic Background */}
      <div className="fixed inset-0 -z-10 pointer-events-none overflow-hidden">
        <div className="absolute -top-40 -left-40 w-[600px] h-[600px] bg-red-600/10 rounded-full blur-[120px] animate-float stagger-1"></div>
        <div className="absolute top-1/2 -right-40 w-[700px] h-[700px] bg-orange-600/10 rounded-full blur-[150px] animate-float stagger-2"></div>
        <div className="absolute -bottom-40 left-1/2 w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-[100px] animate-float stagger-3"></div>
        <div className="absolute inset-0 opacity-[0.02]" style={{backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)', backgroundSize: '32px 32px'}}></div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect } from 'react';
import { GameState, Player, Category } from './types';
import { DEFAULT_CATEGORIES, MIN_PLAYERS, MAX_PLAYERS } from './constants';

const Header = () => (
  <header className="py-12 text-center animate-in fade-in zoom-in duration-1000">
    <div className="inline-block relative">
      <h1 className="text-7xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 via-orange-500 to-yellow-500 drop-shadow-2xl">
        IMPOSTER
      </h1>
      <div className="absolute -inset-1 bg-gradient-to-r from-red-500 to-orange-500 rounded-lg blur opacity-20 animate-pulse"></div>
    </div>
    <p className="text-slate-500 mt-4 uppercase tracking-[0.4em] text-[10px] font-extrabold opacity-80 animate-in fade-in slide-in-from-top-2 duration-700 delay-300">
      Trust No One • Find The Spy
    </p>
  </header>
);

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.SETUP);
  const [playerCount, setPlayerCount] = useState<number>(4);
  const [categories, setCategories] = useState<Category[]>(DEFAULT_CATEGORIES);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>(['games']);
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState<number>(0);
  const [isWordVisible, setIsWordVisible] = useState<boolean>(false);
  const [customWordsInput, setCustomWordsInput] = useState<string>('');
  const [isChaosMode, setIsChaosMode] = useState<boolean>(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  // Cleanup effect: If a category is removed but its ID is still in selectedCategoryIds, remove it.
  useEffect(() => {
    const validIds = categories.map(c => c.id);
    setSelectedCategoryIds(prev => prev.filter(id => validIds.includes(id)));
  }, [categories]);

  const installApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setDeferredPrompt(null);
  };

  const startGame = useCallback(() => {
    if (selectedCategoryIds.length === 0) {
      alert("Select at least one category!");
      return;
    }

    const selectedCats = categories.filter(c => selectedCategoryIds.includes(c.id));
    const allWords = selectedCats.flatMap(c => c.words);

    if (allWords.length === 0) {
      alert("No words available in selection.");
      return;
    }

    const secretWord = allWords[Math.floor(Math.random() * allWords.length)];
    let imposterIndices: number[] = [];

    if (isChaosMode && Math.random() < 0.02) {
      const chaosType = Math.random() < 0.5 ? 'ALL' : 'NONE';
      imposterIndices = chaosType === 'ALL' 
        ? Array.from({ length: playerCount }, (_, i) => i) 
        : [];
    } else {
      imposterIndices = [Math.floor(Math.random() * playerCount)];
    }

    const newPlayers: Player[] = Array.from({ length: playerCount }, (_, i) => ({
      id: i + 1,
      name: `Player ${i + 1}`,
      word: imposterIndices.includes(i) ? 'YOU ARE THE IMPOSTER' : secretWord,
      isImposter: imposterIndices.includes(i),
      hasSeenWord: false
    }));

    setPlayers(newPlayers);
    setCurrentPlayerIndex(0);
    setGameState(GameState.PRE_REVEAL);
    setIsWordVisible(false);
  }, [playerCount, selectedCategoryIds, categories, isChaosMode]);

  const toggleCategory = (id: string) => {
    setSelectedCategoryIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(cid => cid !== id);
      }
      return [...prev, id];
    });
  };

  const handleAddCustomWords = () => {
    const newWords = customWordsInput.split(',')
      .map(s => s.trim())
      .filter(s => s.length > 0);

    if (newWords.length === 0) {
      alert("Enter some words separated by commas!");
      return;
    }

    setCategories(prev => {
      const customIdx = prev.findIndex(c => c.id === 'custom_words_added');
      if (customIdx > -1) {
        const updated = [...prev];
        updated[customIdx] = {
          ...updated[customIdx],
          words: [...new Set([...updated[customIdx].words, ...newWords])]
        };
        return updated;
      } else {
        const newCat: Category = {
          id: 'custom_words_added',
          name: 'Custom',
          words: newWords,
          isCustom: true
        };
        return [...prev, newCat];
      }
    });

    setSelectedCategoryIds(prev => {
      if (!prev.includes('custom_words_added')) {
        return [...prev, 'custom_words_added'];
      }
      return prev;
    });

    setCustomWordsInput('');
  };

  const removeCustomWord = (wordToRemove: string) => {
    setCategories(prev => {
      const updated = prev.map(cat => {
        if (cat.id === 'custom_words_added') {
          return {
            ...cat,
            words: cat.words.filter(w => w !== wordToRemove)
          };
        }
        return cat;
      });

      // If Custom category is now empty, remove it entirely
      return updated.filter(cat => cat.id !== 'custom_words_added' || cat.words.length > 0);
    });
  };

  const renderManageCustom = () => {
    const customCategory = categories.find(c => c.id === 'custom_words_added');
    const words = customCategory?.words || [];

    return (
      <div className="max-w-md mx-auto space-y-6 pb-20 px-2 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center justify-between mb-4">
          <button 
            onClick={() => setGameState(GameState.SETUP)}
            className="text-slate-500 hover:text-white flex items-center gap-2 font-black uppercase text-[10px] tracking-widest transition-colors"
          >
            ← Back
          </button>
          <h2 className="text-white font-black text-xs uppercase tracking-widest">Custom Database</h2>
        </div>

        <div className="bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
          {words.length === 0 ? (
            <div className="py-12 text-center">
              <p className="text-slate-600 text-[10px] font-black uppercase tracking-widest">Database Empty</p>
              <p className="text-slate-500 text-xs mt-2">Add words on the home screen to see them here.</p>
            </div>
          ) : (
            <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
              {words.map((word, idx) => (
                <div 
                  key={`${word}-${idx}`} 
                  className="flex items-center justify-between p-4 bg-slate-900/50 rounded-2xl border border-slate-800/80 group hover:border-red-500/30 transition-all animate-in fade-in slide-in-from-bottom-2"
                >
                  <span className="text-slate-200 font-bold text-sm tracking-tight">{word}</span>
                  <button 
                    onClick={() => removeCustomWord(word)}
                    className="w-8 h-8 rounded-xl bg-red-900/20 hover:bg-red-600 text-red-500 hover:text-white transition-all flex items-center justify-center active:scale-90"
                  >
                    ×
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="text-center pt-4">
          <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest leading-relaxed">
            These words are saved in your current session.<br/>Deleting them here removes them from play.
          </p>
        </div>
      </div>
    );
  };

  const renderSetup = () => (
    <div className="max-w-md mx-auto space-y-8 pb-20 px-2">
      {/* Install Prompt */}
      {deferredPrompt && (
        <div className="animate-in slide-in-from-top-4 fade-in duration-1000 stagger-1 bg-gradient-to-r from-indigo-600/20 to-violet-600/20 p-4 rounded-2xl border border-indigo-500/30 flex items-center justify-between mb-2 backdrop-blur-md">
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase text-indigo-400">PWA Available</span>
            <span className="text-xs text-slate-300">Install for a better experience</span>
          </div>
          <button 
            onClick={installApp}
            className="px-4 py-1.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-[10px] font-black text-white shadow-lg transition-transform active:scale-95"
          >
            INSTALL
          </button>
        </div>
      )}

      {/* Player Selection - Card 1 */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-1 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl group hover:border-orange-500/30 transition-colors">
        <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6 text-center">Operation Size</label>
        <div className="flex items-center justify-between px-4">
          <button 
            onClick={() => setPlayerCount(Math.max(MIN_PLAYERS, playerCount - 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >-</button>
          <div className="text-center">
            <span className="text-7xl font-black text-white tabular-nums drop-shadow-lg scale-110 block">{playerCount}</span>
            <p className="text-[10px] font-bold text-slate-500 mt-2 uppercase tracking-tighter">Players</p>
          </div>
          <button 
            onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >+</button>
        </div>
      </div>

      {/* Standard Categories - Card 2 */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-2 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500">Categories</label>
          <div className="flex gap-4">
            <button 
              onClick={() => setSelectedCategoryIds(categories.map(c => c.id))}
              className="text-[9px] font-black text-orange-500 hover:text-orange-400 uppercase tracking-tighter"
            >
              Select All
            </button>
            <button 
              onClick={() => setSelectedCategoryIds([])}
              className="text-[9px] font-black text-slate-500 hover:text-slate-400 uppercase tracking-tighter"
            >
              Clear
            </button>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          {categories.map(cat => {
            const isSelected = selectedCategoryIds.includes(cat.id);
            return (
              <button
                key={cat.id}
                onClick={() => toggleCategory(cat.id)}
                className={`p-4 rounded-2xl border-2 text-sm font-bold transition-all relative overflow-hidden active:scale-95 ${
                  isSelected 
                    ? 'bg-orange-500/10 border-orange-500 text-white shadow-xl shadow-orange-500/10' 
                    : 'bg-slate-900/50 border-slate-800 text-slate-500 hover:border-slate-600'
                }`}
              >
                {cat.name}
                {cat.id === 'custom_words_added' && (
                  <span className="ml-1 text-[8px] opacity-60">({cat.words.length})</span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Custom Words - Prominent Centered Block */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-3 bg-gradient-to-br from-indigo-900/20 to-violet-900/20 p-8 rounded-[3rem] border border-indigo-500/20 backdrop-blur-xl shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 -mr-10 -mt-10 w-40 h-40 bg-indigo-500/10 rounded-full blur-[60px] group-hover:bg-indigo-500/20 transition-all duration-700"></div>

        <div className="flex justify-between items-center mb-4 relative z-10">
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400">Custom Content</p>
          <button 
            onClick={() => setGameState(GameState.MANAGE_CUSTOM)}
            className="text-[10px] font-black uppercase tracking-widest text-violet-400 hover:text-violet-300 transition-colors bg-violet-500/10 px-3 py-1 rounded-full border border-violet-500/20"
          >
            Manage Data →
          </button>
        </div>

        <div className="relative z-10">
          <textarea
            value={customWordsInput}
            onChange={(e) => setCustomWordsInput(e.target.value)}
            placeholder="Enter words separated by commas (e.g. Laser, Disco, Robot)..."
            className="w-full bg-slate-950/60 border border-slate-800/80 rounded-[2rem] p-6 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none text-slate-100 placeholder:text-slate-700 min-h-[120px] resize-none shadow-inner transition-all hover:bg-slate-950/80"
          />
          <button
            onClick={handleAddCustomWords}
            className="mt-4 w-full py-4 rounded-2xl bg-indigo-600 hover:bg-indigo-500 text-[10px] font-black text-white tracking-[0.2em] transition-all active:scale-95 shadow-xl shadow-indigo-950/40 uppercase"
          >
            Append to Database
          </button>
        </div>
      </div>

      {/* Chaos Mode Toggle */}
      <div 
        className={`animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-3 p-6 rounded-3xl border transition-all duration-500 backdrop-blur-xl flex items-center justify-between group cursor-pointer shadow-xl ${
          isChaosMode ? 'bg-red-950/20 border-red-500/50 shadow-red-500/20' : 'bg-slate-800/40 border-slate-700/50'
        }`}
        onClick={() => setIsChaosMode(!isChaosMode)}
      >
        <div className="flex-1">
          <div className="flex items-center gap-2">
            <span className={`text-[10px] font-black uppercase tracking-widest ${isChaosMode ? 'text-red-400' : 'text-slate-500'}`}>Chaos Mode</span>
            {isChaosMode && <span className="animate-pulse w-2 h-2 bg-red-500 rounded-full"></span>}
          </div>
          <p className="text-[9px] text-slate-600 font-bold mt-1 uppercase tracking-tighter">Extreme outcomes (2% chance)</p>
        </div>
        <div className={`w-14 h-8 rounded-full transition-all duration-300 relative border ${isChaosMode ? 'bg-red-600 border-red-400' : 'bg-slate-900 border-slate-700'}`}>
          <div className={`absolute top-1 bottom-1 w-6 rounded-full transition-all duration-300 ${isChaosMode ? 'right-1 bg-white' : 'left-1 bg-slate-600'}`} />
        </div>
      </div>

      <button
        onClick={startGame}
        className="animate-in slide-in-from-bottom-12 fade-in duration-1000 stagger-4 w-full py-7 rounded-[2.5rem] bg-gradient-to-r from-red-600 via-orange-600 to-orange-500 text-white font-black text-2xl hover:scale-[1.02] transition-all active:scale-95 shadow-2xl shadow-orange-900/40 border-t border-white/20"
      >
        START GAME
      </button>
    </div>
  );

  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-500 mt-10">
      <div className="space-y-4">
        <p className="text-slate-500 uppercase tracking-[0.3em] text-[10px] font-black">Pass the phone to</p>
        <h2 className="text-7xl font-black text-white tracking-tighter drop-shadow-2xl">{players[currentPlayerIndex].name}</h2>
      </div>
      <div className="relative flex items-center justify-center py-10">
        <div className="absolute inset-0 bg-orange-500/10 blur-[120px] rounded-full"></div>
        <div className="relative p-14 bg-slate-800/40 rounded-full border-2 border-dashed border-slate-700/50">
          <span className="text-8xl block animate-bounce">📱</span>
        </div>
      </div>
      <button
        onClick={() => setGameState(GameState.REVEALING)}
        className="w-full py-7 rounded-[2rem] bg-white text-slate-950 font-black text-2xl shadow-2xl transition-all active:scale-95 hover:bg-slate-100"
      >
        I AM READY
      </button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-10 animate-in fade-in duration-300 mt-10">
      <div className="space-y-2">
        <h3 className="text-orange-500 font-black uppercase text-[10px] tracking-[0.4em]">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Tap to reveal identity</p>
      </div>
      <div 
        onClick={() => setIsWordVisible(!isWordVisible)}
        className={`relative h-[24rem] rounded-[3rem] cursor-pointer transition-all duration-700 flex items-center justify-center overflow-hidden border-2 ${
          isWordVisible 
            ? 'bg-white border-white' 
            : 'bg-slate-900 border-slate-800 hover:border-slate-700 shadow-2xl'
        }`}
      >
        {isWordVisible ? (
          <div className="text-center p-10 animate-in zoom-in-90 duration-300">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-400 mb-6 opacity-60">Secret Assignment</p>
            <span className={`text-5xl font-black tracking-tight leading-tight ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-950'}`}>
              {players[currentPlayerIndex].word}
            </span>
          </div>
        ) : (
          <div className="text-center group p-10">
            <div className="text-9xl mb-8 opacity-20 filter grayscale">🕵️</div>
            <p className="font-black text-slate-600 tracking-[0.2em] text-xs uppercase">Hold to reveal</p>
          </div>
        )}
      </div>
      {isWordVisible && (
        <button
          onClick={() => {
            if (currentPlayerIndex < playerCount - 1) {
              setCurrentPlayerIndex(prev => prev + 1);
              setGameState(GameState.PRE_REVEAL);
              setIsWordVisible(false);
            } else {
              setGameState(GameState.DISCUSSION);
            }
          }}
          className="w-full py-6 rounded-[2rem] bg-orange-600 text-white font-black text-xl shadow-xl transition-all active:scale-95 animate-in slide-in-from-bottom-8 duration-500"
        >
          I'VE SEEN IT
        </button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-1000 mt-10">
      <div className="space-y-4">
        <div className="inline-block px-4 py-1.5 rounded-full bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-black tracking-[0.3em] uppercase mb-4">Live Mission</div>
        <h2 className="text-6xl font-black text-white tracking-tighter leading-none">DISCUSSION</h2>
        <p className="text-slate-500 text-xs leading-relaxed font-bold uppercase tracking-wide px-6">
          Find the spy before they figure out the secret word.
        </p>
      </div>
      <div className="grid grid-cols-2 gap-4">
        {players.map(p => (
          <div key={p.id} className="p-5 bg-slate-900/60 rounded-[1.5rem] border border-slate-800/80 text-slate-400 font-black transition-all hover:bg-slate-800">
            <span className="text-[9px] block opacity-40 uppercase mb-1">Agent {p.id}</span>
            {p.name}
          </div>
        ))}
      </div>
      <div className="pt-10">
        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-5 rounded-[2rem] bg-slate-800/50 text-slate-400 font-black text-xs uppercase tracking-[0.3em] hover:bg-slate-800 hover:text-white transition-all border border-slate-700/50"
        >
          FINISH GAME
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen relative selection:bg-orange-500/30 overflow-hidden pb-10">
      <div className="max-w-4xl mx-auto relative z-20 px-4">
        <Header />
        <main>
          {gameState === GameState.SETUP && renderSetup()}
          {gameState === GameState.PRE_REVEAL && renderPreReveal()}
          {gameState === GameState.REVEALING && renderRevealing()}
          {gameState === GameState.DISCUSSION && renderDiscussion()}
          {gameState === GameState.MANAGE_CUSTOM && renderManageCustom()}
        </main>
      </div>

      {/* Dynamic Background */}
      <div className="fixed inset-0 -z-10 pointer-events-none overflow-hidden">
        <div className="absolute -top-40 -left-40 w-[600px] h-[600px] bg-red-600/10 rounded-full blur-[120px] animate-float stagger-1"></div>
        <div className="absolute top-1/2 -right-40 w-[700px] h-[700px] bg-orange-600/10 rounded-full blur-[150px] animate-float stagger-2"></div>
        <div className="absolute -bottom-40 left-1/2 w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-[100px] animate-float stagger-3"></div>
        <div className="absolute inset-0 opacity-[0.02]" style={{backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)', backgroundSize: '32px 32px'}}></div>
      </div>
    </div>
  );
};

export default App;

export interface Category {
  id: string;
  name: string;
  words: string[];
  isCustom?: boolean;
}

export interface Player {
  id: number;
  name: string;
  word: string;
  isImposter: boolean;
  hasSeenWord: boolean;
}

export enum GameState {
  SETUP = 'SETUP',
  PRE_REVEAL = 'PRE_REVEAL',
  REVEALING = 'REVEALING',
  DISCUSSION = 'DISCUSSION',
  MANAGE_CUSTOM = 'MANAGE_CUSTOM',
  PICK_WORDS = 'PICK_WORDS'
}

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { GameState, Player, Category } from './types';
import { DEFAULT_CATEGORIES, MIN_PLAYERS, MAX_PLAYERS } from './constants';

const Header = () => (
  <header className="py-12 text-center animate-in fade-in zoom-in duration-1000">
    <div className="inline-block relative">
      <h1 className="text-7xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 via-orange-500 to-yellow-500 drop-shadow-2xl">
        IMPOSTER
      </h1>
      <div className="absolute -inset-1 bg-gradient-to-r from-red-500 to-orange-500 rounded-lg blur opacity-20 animate-pulse"></div>
    </div>
    <p className="text-slate-500 mt-4 uppercase tracking-[0.4em] text-[10px] font-extrabold opacity-80 animate-in fade-in slide-in-from-top-2 duration-700 delay-300">
      Trust No One • Find The Spy
    </p>
  </header>
);

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.SETUP);
  const [playerCount, setPlayerCount] = useState<number>(4);
  const [categories, setCategories] = useState<Category[]>(DEFAULT_CATEGORIES);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>(['games']);
  const [wordOverrides, setWordOverrides] = useState<Record<string, string[]>>({});
  const [activePickingCategory, setActivePickingCategory] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState<number>(0);
  const [isWordVisible, setIsWordVisible] = useState<boolean>(false);
  const [customWordsInput, setCustomWordsInput] = useState<string>('');
  const [isChaosMode, setIsChaosMode] = useState<boolean>(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  useEffect(() => {
    const validIds = categories.map(c => c.id);
    setSelectedCategoryIds(prev => prev.filter(id => validIds.includes(id)));
    // Also clean up overrides for deleted categories
    setWordOverrides(prev => {
      const next = { ...prev };
      Object.keys(next).forEach(id => {
        if (!validIds.includes(id)) delete next[id];
      });
      return next;
    });
  }, [categories]);

  const installApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setDeferredPrompt(null);
  };

  const startGame = useCallback(() => {
    if (selectedCategoryIds.length === 0) {
      alert("Select at least one category!");
      return;
    }

    const allPlayableWords: string[] = [];
    selectedCategoryIds.forEach(id => {
      const category = categories.find(c => c.id === id);
      if (category) {
        const overrides = wordOverrides[id];
        if (overrides && overrides.length > 0) {
          allPlayableWords.push(...overrides);
        } else {
          allPlayableWords.push(...category.words);
        }
      }
    });

    if (allPlayableWords.length === 0) {
      alert("No words available in current selection. Check your word filters!");
      return;
    }

    const secretWord = allPlayableWords[Math.floor(Math.random() * allPlayableWords.length)];
    let imposterIndices: number[] = [];

    if (isChaosMode && Math.random() < 0.02) {
      const chaosType = Math.random() < 0.5 ? 'ALL' : 'NONE';
      imposterIndices = chaosType === 'ALL' 
        ? Array.from({ length: playerCount }, (_, i) => i) 
        : [];
    } else {
      imposterIndices = [Math.floor(Math.random() * playerCount)];
    }

    const newPlayers: Player[] = Array.from({ length: playerCount }, (_, i) => ({
      id: i + 1,
      name: `Player ${i + 1}`,
      word: imposterIndices.includes(i) ? 'YOU ARE THE IMPOSTER' : secretWord,
      isImposter: imposterIndices.includes(i),
      hasSeenWord: false
    }));

    setPlayers(newPlayers);
    setCurrentPlayerIndex(0);
    setGameState(GameState.PRE_REVEAL);
    setIsWordVisible(false);
  }, [playerCount, selectedCategoryIds, categories, isChaosMode, wordOverrides]);

  const toggleCategory = (id: string) => {
    setSelectedCategoryIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(cid => cid !== id);
      }
      return [...prev, id];
    });
  };

  const handleAddCustomWords = () => {
    const newWords = customWordsInput.split(',')
      .map(s => s.trim())
      .filter(s => s.length > 0);

    if (newWords.length === 0) {
      alert("Enter some words separated by commas!");
      return;
    }

    setCategories(prev => {
      const customIdx = prev.findIndex(c => c.id === 'custom_words_added');
      if (customIdx > -1) {
        const updated = [...prev];
        updated[customIdx] = {
          ...updated[customIdx],
          words: [...new Set([...updated[customIdx].words, ...newWords])]
        };
        return updated;
      } else {
        const newCat: Category = {
          id: 'custom_words_added',
          name: 'Custom',
          words: newWords,
          isCustom: true
        };
        return [...prev, newCat];
      }
    });

    setSelectedCategoryIds(prev => {
      if (!prev.includes('custom_words_added')) return [...prev, 'custom_words_added'];
      return prev;
    });

    setCustomWordsInput('');
  };

  const removeCustomWord = (wordToRemove: string) => {
    setCategories(prev => {
      const updated = prev.map(cat => {
        if (cat.id === 'custom_words_added') {
          return {
            ...cat,
            words: cat.words.filter(w => w !== wordToRemove)
          };
        }
        return cat;
      });
      return updated.filter(cat => cat.id !== 'custom_words_added' || cat.words.length > 0);
    });
    // Also remove from overrides if present
    setWordOverrides(prev => {
      const current = prev['custom_words_added'] || [];
      return {
        ...prev,
        'custom_words_added': current.filter(w => w !== wordToRemove)
      };
    });
  };

  const enterWordPicking = (categoryId: string) => {
    setActivePickingCategory(categoryId);
    setGameState(GameState.PICK_WORDS);
  };

  const renderPickWords = () => {
    const category = categories.find(c => c.id === activePickingCategory);
    if (!category) return null;

    const currentSelection = wordOverrides[category.id] || category.words;

    const toggleWord = (word: string) => {
      setWordOverrides(prev => {
        const existing = prev[category.id] || [...category.words];
        if (existing.includes(word)) {
          const next = existing.filter(w => w !== word);
          return { ...prev, [category.id]: next };
        } else {
          return { ...prev, [category.id]: [...existing, word] };
        }
      });
    };

    return (
      <div className="max-w-md mx-auto space-y-6 pb-20 px-2 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center justify-between mb-4">
          <button 
            onClick={() => setGameState(GameState.SETUP)}
            className="text-slate-500 hover:text-white flex items-center gap-2 font-black uppercase text-[10px] tracking-widest transition-colors"
          >
            ← Back
          </button>
          <h2 className="text-white font-black text-xs uppercase tracking-widest">Filter: {category.name}</h2>
        </div>

        <div className="bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
          <div className="flex justify-between items-center mb-6 px-2">
            <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">
              {currentSelection.length} / {category.words.length} Selected
            </span>
            <div className="flex gap-4">
              <button 
                onClick={() => setWordOverrides(prev => ({ ...prev, [category.id]: [...category.words] }))}
                className="text-[9px] font-black text-orange-500 uppercase tracking-tighter"
              >
                Select All
              </button>
              <button 
                onClick={() => setWordOverrides(prev => ({ ...prev, [category.id]: [] }))}
                className="text-[9px] font-black text-slate-500 uppercase tracking-tighter"
              >
                Clear
              </button>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-2 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            {category.words.map((word, idx) => {
              const isSelected = currentSelection.includes(word);
              return (
                <button 
                  key={`${word}-${idx}`} 
                  onClick={() => toggleWord(word)}
                  className={`p-3 rounded-xl border text-[11px] font-bold text-left transition-all relative overflow-hidden ${
                    isSelected 
                      ? 'bg-orange-500/10 border-orange-500/50 text-white shadow-lg shadow-orange-500/5' 
                      : 'bg-slate-900/50 border-slate-800 text-slate-600'
                  }`}
                >
                  {word}
                </button>
              );
            })}
          </div>
        </div>

        <button 
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-4 rounded-2xl bg-white text-slate-950 font-black text-xs uppercase tracking-[0.3em] hover:bg-slate-100 transition-all shadow-2xl"
        >
          DONE
        </button>
      </div>
    );
  };

  const renderManageCustom = () => {
    const customCategory = categories.find(c => c.id === 'custom_words_added');
    const words = customCategory?.words || [];

    return (
      <div className="max-w-md mx-auto space-y-6 pb-20 px-2 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center justify-between mb-4">
          <button 
            onClick={() => setGameState(GameState.SETUP)}
            className="text-slate-500 hover:text-white flex items-center gap-2 font-black uppercase text-[10px] tracking-widest transition-colors"
          >
            ← Back
          </button>
          <h2 className="text-white font-black text-xs uppercase tracking-widest">Custom Database</h2>
        </div>

        <div className="bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
          {words.length === 0 ? (
            <div className="py-12 text-center">
              <p className="text-slate-600 text-[10px] font-black uppercase tracking-widest">Database Empty</p>
              <p className="text-slate-500 text-xs mt-2">Add words on the home screen to see them here.</p>
            </div>
          ) : (
            <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
              {words.map((word, idx) => (
                <div 
                  key={`${word}-${idx}`} 
                  className="flex items-center justify-between p-4 bg-slate-900/50 rounded-2xl border border-slate-800/80 group hover:border-red-500/30 transition-all animate-in fade-in slide-in-from-bottom-2"
                >
                  <span className="text-slate-200 font-bold text-sm tracking-tight">{word}</span>
                  <button 
                    onClick={() => removeCustomWord(word)}
                    className="w-8 h-8 rounded-xl bg-red-900/20 hover:bg-red-600 text-red-500 hover:text-white transition-all flex items-center justify-center active:scale-90"
                  >
                    ×
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="text-center pt-4">
          <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest leading-relaxed">
            These words are saved in your current session.<br/>Deleting them here removes them from play.
          </p>
        </div>
      </div>
    );
  };

  const renderSetup = () => (
    <div className="max-w-md mx-auto space-y-8 pb-20 px-2">
      {/* Install Prompt */}
      {deferredPrompt && (
        <div className="animate-in slide-in-from-top-4 fade-in duration-1000 stagger-1 bg-gradient-to-r from-indigo-600/20 to-violet-600/20 p-4 rounded-2xl border border-indigo-500/30 flex items-center justify-between mb-2 backdrop-blur-md">
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase text-indigo-400">PWA Available</span>
            <span className="text-xs text-slate-300">Install for a better experience</span>
          </div>
          <button 
            onClick={installApp}
            className="px-4 py-1.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-[10px] font-black text-white shadow-lg transition-transform active:scale-95"
          >
            INSTALL
          </button>
        </div>
      )}

      {/* Player Selection - Card 1 */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-1 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl group hover:border-orange-500/30 transition-colors">
        <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6 text-center">Operation Size</label>
        <div className="flex items-center justify-between px-4">
          <button 
            onClick={() => setPlayerCount(Math.max(MIN_PLAYERS, playerCount - 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >-</button>
          <div className="text-center">
            <span className="text-7xl font-black text-white tabular-nums drop-shadow-lg scale-110 block">{playerCount}</span>
            <p className="text-[10px] font-bold text-slate-500 mt-2 uppercase tracking-tighter">Players</p>
          </div>
          <button 
            onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))}
            className="w-16 h-16 rounded-2xl bg-slate-900/80 hover:bg-slate-800 transition-all text-2xl font-black text-white active:scale-90 border border-slate-700/50 shadow-inner"
          >+</button>
        </div>
      </div>

      {/* Standard Categories - Card 2 */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-2 bg-slate-800/40 p-6 rounded-[2.5rem] border border-slate-700/50 backdrop-blur-xl shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500">Categories</label>
          <div className="flex gap-4">
            <button 
              onClick={() => setSelectedCategoryIds(categories.map(c => c.id))}
              className="text-[9px] font-black text-orange-500 hover:text-orange-400 uppercase tracking-tighter"
            >
              Select All
            </button>
            <button 
              onClick={() => setSelectedCategoryIds([])}
              className="text-[9px] font-black text-slate-500 hover:text-slate-400 uppercase tracking-tighter"
            >
              Clear
            </button>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          {categories.map(cat => {
            const isSelected = selectedCategoryIds.includes(cat.id);
            const hasOverrides = wordOverrides[cat.id] && wordOverrides[cat.id].length < cat.words.length;

            return (
              <div key={cat.id} className="relative group">
                <button
                  onClick={() => toggleCategory(cat.id)}
                  className={`w-full p-4 pr-10 rounded-2xl border-2 text-sm font-bold transition-all relative overflow-hidden active:scale-95 text-left h-20 flex flex-col justify-center ${
                    isSelected 
                      ? 'bg-orange-500/10 border-orange-500 text-white shadow-xl shadow-orange-500/10' 
                      : 'bg-slate-900/50 border-slate-800 text-slate-500 hover:border-slate-600'
                  }`}
                >
                  <span className="truncate w-full">{cat.name}</span>
                  {isSelected && (
                    <span className="text-[8px] opacity-60 mt-1 uppercase tracking-widest">
                      {wordOverrides[cat.id]?.length ?? cat.words.length} Words
                    </span>
                  )}
                </button>
                {isSelected && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); enterWordPicking(cat.id); }}
                    className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 rounded-xl bg-orange-500/20 hover:bg-orange-500 text-orange-500 hover:text-white flex items-center justify-center transition-all z-10"
                    title="Select specific words"
                  >
                    <span className="text-xs">⚙️</span>
                  </button>
                )}
                {hasOverrides && isSelected && (
                  <div className="absolute top-2 left-2 w-1.5 h-1.5 bg-orange-500 rounded-full animate-pulse shadow-lg shadow-orange-500/50"></div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Custom Words - Card 3 */}
      <div className="animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-3 bg-gradient-to-br from-indigo-900/20 to-violet-900/20 p-8 rounded-[3rem] border border-indigo-500/20 backdrop-blur-xl shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 -mr-10 -mt-10 w-40 h-40 bg-indigo-500/10 rounded-full blur-[60px] group-hover:bg-indigo-500/20 transition-all duration-700"></div>

        <div className="flex justify-between items-center mb-4 relative z-10">
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400">Custom Content</p>
          <button 
            onClick={() => setGameState(GameState.MANAGE_CUSTOM)}
            className="text-[10px] font-black uppercase tracking-widest text-violet-400 hover:text-violet-300 transition-colors bg-violet-500/10 px-3 py-1 rounded-full border border-violet-500/20"
          >
            Manage Data →
          </button>
        </div>

        <div className="relative z-10">
          <textarea
            value={customWordsInput}
            onChange={(e) => setCustomWordsInput(e.target.value)}
            placeholder="Enter words separated by commas (e.g. Laser, Disco, Robot)..."
            className="w-full bg-slate-950/60 border border-slate-800/80 rounded-[2rem] p-6 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none text-slate-100 placeholder:text-slate-700 min-h-[120px] resize-none shadow-inner transition-all hover:bg-slate-950/80"
          />
          <button
            onClick={handleAddCustomWords}
            className="mt-4 w-full py-4 rounded-2xl bg-indigo-600 hover:bg-indigo-500 text-[10px] font-black text-white tracking-[0.2em] transition-all active:scale-95 shadow-xl shadow-indigo-950/40 uppercase"
          >
            Append to Database
          </button>
        </div>
      </div>

      {/* Chaos Mode Toggle */}
      <div 
        className={`animate-in slide-in-from-bottom-8 fade-in duration-700 stagger-3 p-6 rounded-3xl border transition-all duration-500 backdrop-blur-xl flex items-center justify-between group cursor-pointer shadow-xl ${
          isChaosMode ? 'bg-red-950/20 border-red-500/50 shadow-red-500/20' : 'bg-slate-800/40 border-slate-700/50'
        }`}
        onClick={() => setIsChaosMode(!isChaosMode)}
      >
        <div className="flex-1">
          <div className="flex items-center gap-2">
            <span className={`text-[10px] font-black uppercase tracking-widest ${isChaosMode ? 'text-red-400' : 'text-slate-500'}`}>Chaos Mode</span>
            {isChaosMode && <span className="animate-pulse w-2 h-2 bg-red-500 rounded-full"></span>}
          </div>
          <p className="text-[9px] text-slate-600 font-bold mt-1 uppercase tracking-tighter">Extreme outcomes (2% chance)</p>
        </div>
        <div className={`w-14 h-8 rounded-full transition-all duration-300 relative border ${isChaosMode ? 'bg-red-600 border-red-400' : 'bg-slate-900 border-slate-700'}`}>
          <div className={`absolute top-1 bottom-1 w-6 rounded-full transition-all duration-300 ${isChaosMode ? 'right-1 bg-white' : 'left-1 bg-slate-600'}`} />
        </div>
      </div>

      <button
        onClick={startGame}
        className="animate-in slide-in-from-bottom-12 fade-in duration-1000 stagger-4 w-full py-7 rounded-[2.5rem] bg-gradient-to-r from-red-600 via-orange-600 to-orange-500 text-white font-black text-2xl hover:scale-[1.02] transition-all active:scale-95 shadow-2xl shadow-orange-900/40 border-t border-white/20"
      >
        START GAME
      </button>
    </div>
  );

  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-500 mt-10">
      <div className="space-y-4">
        <p className="text-slate-500 uppercase tracking-[0.3em] text-[10px] font-black">Pass the phone to</p>
        <h2 className="text-7xl font-black text-white tracking-tighter drop-shadow-2xl">{players[currentPlayerIndex].name}</h2>
      </div>
      <div className="relative flex items-center justify-center py-10">
        <div className="absolute inset-0 bg-orange-500/10 blur-[120px] rounded-full"></div>
        <div className="relative p-14 bg-slate-800/40 rounded-full border-2 border-dashed border-slate-700/50">
          <span className="text-8xl block animate-bounce">📱</span>
        </div>
      </div>
      <button
        onClick={() => setGameState(GameState.REVEALING)}
        className="w-full py-7 rounded-[2rem] bg-white text-slate-950 font-black text-2xl shadow-2xl transition-all active:scale-95 hover:bg-slate-100"
      >
        I AM READY
      </button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-10 animate-in fade-in duration-300 mt-10">
      <div className="space-y-2">
        <h3 className="text-orange-500 font-black uppercase text-[10px] tracking-[0.4em]">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Tap to reveal identity</p>
      </div>
      <div 
        onClick={() => setIsWordVisible(!isWordVisible)}
        className={`relative h-[24rem] rounded-[3rem] cursor-pointer transition-all duration-700 flex items-center justify-center overflow-hidden border-2 ${
          isWordVisible 
            ? 'bg-white border-white' 
            : 'bg-slate-900 border-slate-800 hover:border-slate-700 shadow-2xl'
        }`}
      >
        {isWordVisible ? (
          <div className="text-center p-10 animate-in zoom-in-90 duration-300">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-400 mb-6 opacity-60">Secret Assignment</p>
            <span className={`text-5xl font-black tracking-tight leading-tight ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-950'}`}>
              {players[currentPlayerIndex].word}
            </span>
          </div>
        ) : (
          <div className="text-center group p-10">
            <div className="text-9xl mb-8 opacity-20 filter grayscale">🕵️</div>
            <p className="font-black text-slate-600 tracking-[0.2em] text-xs uppercase">Hold to reveal</p>
          </div>
        )}
      </div>
      {isWordVisible && (
        <button
          onClick={() => {
            if (currentPlayerIndex < playerCount - 1) {
              setCurrentPlayerIndex(prev => prev + 1);
              setGameState(GameState.PRE_REVEAL);
              setIsWordVisible(false);
            } else {
              setGameState(GameState.DISCUSSION);
            }
          }}
          className="w-full py-6 rounded-[2rem] bg-orange-600 text-white font-black text-xl shadow-xl transition-all active:scale-95 animate-in slide-in-from-bottom-8 duration-500"
        >
          I'VE SEEN IT
        </button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-12 animate-in fade-in zoom-in-95 duration-1000 mt-10">
      <div className="space-y-4">
        <div className="inline-block px-4 py-1.5 rounded-full bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-black tracking-[0.3em] uppercase mb-4">Live Mission</div>
        <h2 className="text-6xl font-black text-white tracking-tighter leading-none">DISCUSSION</h2>
        <p className="text-slate-500 text-xs leading-relaxed font-bold uppercase tracking-wide px-6">
          Find the spy before they figure out the secret word.
        </p>
      </div>
      <div className="grid grid-cols-2 gap-4">
        {players.map(p => (
          <div key={p.id} className="p-5 bg-slate-900/60 rounded-[1.5rem] border border-slate-800/80 text-slate-400 font-black transition-all hover:bg-slate-800">
            <span className="text-[9px] block opacity-40 uppercase mb-1">Agent {p.id}</span>
            {p.name}
          </div>
        ))}
      </div>
      <div className="pt-10">
        <button
          onClick={() => setGameState(GameState.SETUP)}
          className="w-full py-5 rounded-[2rem] bg-slate-800/50 text-slate-400 font-black text-xs uppercase tracking-[0.3em] hover:bg-slate-800 hover:text-white transition-all border border-slate-700/50"
        >
          FINISH GAME
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen relative selection:bg-orange-500/30 overflow-hidden pb-10">
      <div className="max-w-4xl mx-auto relative z-20 px-4">
        <Header />
        <main>
          {gameState === GameState.SETUP && renderSetup()}
          {gameState === GameState.PRE_REVEAL && renderPreReveal()}
          {gameState === GameState.REVEALING && renderRevealing()}
          {gameState === GameState.DISCUSSION && renderDiscussion()}
          {gameState === GameState.MANAGE_CUSTOM && renderManageCustom()}
          {gameState === GameState.PICK_WORDS && renderPickWords()}
        </main>
      </div>

      {/* Dynamic Background */}
      <div className="fixed inset-0 -z-10 pointer-events-none overflow-hidden">
        <div className="absolute -top-40 -left-40 w-[600px] h-[600px] bg-red-600/10 rounded-full blur-[120px] animate-float stagger-1"></div>
        <div className="absolute top-1/2 -right-40 w-[700px] h-[700px] bg-orange-600/10 rounded-full blur-[150px] animate-float stagger-2"></div>
        <div className="absolute -bottom-40 left-1/2 w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-[100px] animate-float stagger-3"></div>
        <div className="absolute inset-0 opacity-[0.02]" style={{backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)', backgroundSize: '32px 32px'}}></div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect } from 'react';
import { GameState, Player, Category } from './types';
import { DEFAULT_CATEGORIES, MIN_PLAYERS, MAX_PLAYERS } from './constants';

const Header = () => (
  <header className="py-6 text-center animate-in fade-in zoom-in duration-700">
    <div className="inline-block relative">
      <h1 className="text-5xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 via-orange-500 to-yellow-500 drop-shadow-xl">
        IMPOSTER
      </h1>
      <div className="absolute -inset-1 bg-gradient-to-r from-red-500 to-orange-500 rounded-lg blur opacity-10 animate-pulse"></div>
    </div>
    <p className="text-slate-500 mt-2 uppercase tracking-[0.3em] text-[8px] font-extrabold opacity-70">
      Trust No One • Find The Spy
    </p>
  </header>
);

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.SETUP);
  const [playerCount, setPlayerCount] = useState<number>(4);
  const [categories, setCategories] = useState<Category[]>(DEFAULT_CATEGORIES);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>(['games']);
  const [wordOverrides, setWordOverrides] = useState<Record<string, string[]>>({});
  const [activePickingCategory, setActivePickingCategory] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState<number>(0);
  const [isWordVisible, setIsWordVisible] = useState<boolean>(false);
  const [customWordsInput, setCustomWordsInput] = useState<string>('');
  const [isChaosMode, setIsChaosMode] = useState<boolean>(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  useEffect(() => {
    const validIds = categories.map(c => c.id);
    setSelectedCategoryIds(prev => prev.filter(id => validIds.includes(id)));
    setWordOverrides(prev => {
      const next = { ...prev };
      Object.keys(next).forEach(id => {
        if (!validIds.includes(id)) delete next[id];
      });
      return next;
    });
  }, [categories]);

  const installApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setDeferredPrompt(null);
  };

  const startGame = useCallback(() => {
    if (selectedCategoryIds.length === 0) {
      alert("Select at least one category!");
      return;
    }

    const allPlayableWords: string[] = [];
    selectedCategoryIds.forEach(id => {
      const category = categories.find(c => c.id === id);
      if (category) {
        const overrides = wordOverrides[id];
        if (overrides && overrides.length > 0) {
          allPlayableWords.push(...overrides);
        } else {
          allPlayableWords.push(...category.words);
        }
      }
    });

    if (allPlayableWords.length === 0) {
      alert("No words available in current selection.");
      return;
    }

    const secretWord = allPlayableWords[Math.floor(Math.random() * allPlayableWords.length)];
    let imposterIndices: number[] = [];

    if (isChaosMode && Math.random() < 0.02) {
      const chaosType = Math.random() < 0.5 ? 'ALL' : 'NONE';
      imposterIndices = chaosType === 'ALL' 
        ? Array.from({ length: playerCount }, (_, i) => i) 
        : [];
    } else {
      imposterIndices = [Math.floor(Math.random() * playerCount)];
    }

    const newPlayers: Player[] = Array.from({ length: playerCount }, (_, i) => ({
      id: i + 1,
      name: `Player ${i + 1}`,
      word: imposterIndices.includes(i) ? 'YOU ARE THE IMPOSTER' : secretWord,
      isImposter: imposterIndices.includes(i),
      hasSeenWord: false
    }));

    setPlayers(newPlayers);
    setCurrentPlayerIndex(0);
    setGameState(GameState.PRE_REVEAL);
    setIsWordVisible(false);
  }, [playerCount, selectedCategoryIds, categories, isChaosMode, wordOverrides]);

  const toggleCategory = (id: string) => {
    setSelectedCategoryIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(cid => cid !== id);
      }
      return [...prev, id];
    });
  };

  const handleAddCustomWords = () => {
    const newWords = customWordsInput.split(',')
      .map(s => s.trim())
      .filter(s => s.length > 0);

    if (newWords.length === 0) {
      alert("Enter some words separated by commas!");
      return;
    }

    setCategories(prev => {
      const customIdx = prev.findIndex(c => c.id === 'custom_words_added');
      if (customIdx > -1) {
        const updated = [...prev];
        updated[customIdx] = {
          ...updated[customIdx],
          words: [...new Set([...updated[customIdx].words, ...newWords])]
        };
        return updated;
      } else {
        const newCat: Category = {
          id: 'custom_words_added',
          name: 'Custom',
          words: newWords,
          isCustom: true
        };
        return [...prev, newCat];
      }
    });

    setSelectedCategoryIds(prev => {
      if (!prev.includes('custom_words_added')) return [...prev, 'custom_words_added'];
      return prev;
    });

    setCustomWordsInput('');
  };

  const removeCustomWord = (wordToRemove: string) => {
    setCategories(prev => {
      const updated = prev.map(cat => {
        if (cat.id === 'custom_words_added') {
          return {
            ...cat,
            words: cat.words.filter(w => w !== wordToRemove)
          };
        }
        return cat;
      });
      return updated.filter(cat => cat.id !== 'custom_words_added' || cat.words.length > 0);
    });
    setWordOverrides(prev => {
      const current = prev['custom_words_added'] || [];
      return {
        ...prev,
        'custom_words_added': current.filter(w => w !== wordToRemove)
      };
    });
  };

  const enterWordPicking = (categoryId: string) => {
    setActivePickingCategory(categoryId);
    setGameState(GameState.PICK_WORDS);
  };

  const renderPickWords = () => {
    const category = categories.find(c => c.id === activePickingCategory);
    if (!category) return null;
    const currentSelection = wordOverrides[category.id] || category.words;

    const toggleWord = (word: string) => {
      setWordOverrides(prev => {
        const existing = prev[category.id] || [...category.words];
        if (existing.includes(word)) {
          const next = existing.filter(w => w !== word);
          return { ...prev, [category.id]: next };
        } else {
          return { ...prev, [category.id]: [...existing, word] };
        }
      });
    };

    return (
      <div className="max-w-md mx-auto space-y-4 px-2 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setGameState(GameState.SETUP)} className="text-slate-500 font-black uppercase text-[10px] tracking-widest transition-colors">← Back</button>
          <h2 className="text-white font-black text-xs uppercase tracking-widest">{category.name}</h2>
        </div>
        <div className="bg-slate-800/40 p-4 rounded-3xl border border-slate-700/50 backdrop-blur-xl">
          <div className="flex justify-between items-center mb-4">
            <span className="text-[10px] font-black uppercase text-slate-500">{currentSelection.length} / {category.words.length}</span>
            <div className="flex gap-4">
              <button onClick={() => setWordOverrides(prev => ({ ...prev, [category.id]: [...category.words] }))} className="text-[9px] font-black text-orange-500 uppercase">All</button>
              <button onClick={() => setWordOverrides(prev => ({ ...prev, [category.id]: [] }))} className="text-[9px] font-black text-slate-500 uppercase">Clear</button>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2 max-h-[60vh] overflow-y-auto pr-1">
            {category.words.map((word, idx) => {
              const isSelected = currentSelection.includes(word);
              return (
                <button key={`${word}-${idx}`} onClick={() => toggleWord(word)} className={`p-2.5 rounded-xl border text-[10px] font-bold text-left transition-all ${isSelected ? 'bg-orange-500/10 border-orange-500/50 text-white' : 'bg-slate-900/50 border-slate-800 text-slate-600'}`}>
                  {word}
                </button>
              );
            })}
          </div>
        </div>
        <button onClick={() => setGameState(GameState.SETUP)} className="w-full py-4 rounded-2xl bg-white text-slate-950 font-black text-xs uppercase tracking-[0.3em]">DONE</button>
      </div>
    );
  };

  const renderManageCustom = () => {
    const customCategory = categories.find(c => c.id === 'custom_words_added');
    const words = customCategory?.words || [];
    return (
      <div className="max-w-md mx-auto space-y-4 px-2 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setGameState(GameState.SETUP)} className="text-slate-500 font-black uppercase text-[10px] tracking-widest">← Back</button>
          <h2 className="text-white font-black text-xs uppercase tracking-widest">Database</h2>
        </div>
        <div className="bg-slate-800/40 p-4 rounded-3xl border border-slate-700/50 backdrop-blur-xl">
          {words.length === 0 ? (
            <div className="py-8 text-center"><p className="text-slate-600 text-[10px] font-black uppercase">Empty</p></div>
          ) : (
            <div className="space-y-1.5 max-h-[60vh] overflow-y-auto pr-1">
              {words.map((word, idx) => (
                <div key={`${word}-${idx}`} className="flex items-center justify-between p-3 bg-slate-900/50 rounded-xl border border-slate-800/80">
                  <span className="text-slate-200 font-bold text-xs">{word}</span>
                  <button onClick={() => removeCustomWord(word)} className="w-6 h-6 rounded-lg bg-red-900/20 text-red-500 font-black">×</button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderSetup = () => (
    <div className="max-w-md mx-auto space-y-3 pb-8 px-2">
      {/* Player Selection - More Compact */}
      <div className="bg-slate-800/40 p-4 rounded-[2rem] border border-slate-700/50 backdrop-blur-xl shadow-lg">
        <div className="flex items-center justify-between px-2">
          <button onClick={() => setPlayerCount(Math.max(MIN_PLAYERS, playerCount - 1))} className="w-10 h-10 rounded-xl bg-slate-900/80 text-lg font-black text-white active:scale-90 border border-slate-700/50">-</button>
          <div className="text-center">
            <span className="text-4xl font-black text-white tabular-nums leading-none">{playerCount}</span>
            <p className="text-[8px] font-bold text-slate-500 uppercase tracking-tighter">Players</p>
          </div>
          <button onClick={() => setPlayerCount(Math.min(MAX_PLAYERS, playerCount + 1))} className="w-10 h-10 rounded-xl bg-slate-900/80 text-lg font-black text-white active:scale-90 border border-slate-700/50">+</button>
        </div>
      </div>

      {/* Standard Categories - More Compact */}
      <div className="bg-slate-800/40 p-4 rounded-[2rem] border border-slate-700/50 backdrop-blur-xl shadow-lg">
        <div className="flex justify-between items-center mb-3 px-1">
          <label className="text-[9px] font-black uppercase tracking-widest text-slate-500">Categories</label>
          <div className="flex gap-3">
            <button onClick={() => setSelectedCategoryIds(categories.map(c => c.id))} className="text-[8px] font-black text-orange-500 uppercase">All</button>
            <button onClick={() => setSelectedCategoryIds([])} className="text-[8px] font-black text-slate-500 uppercase">Clear</button>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-2">
          {categories.map(cat => {
            const isSelected = selectedCategoryIds.includes(cat.id);
            const hasOverrides = wordOverrides[cat.id] && wordOverrides[cat.id].length < cat.words.length;
            return (
              <div key={cat.id} className="relative">
                <button
                  onClick={() => toggleCategory(cat.id)}
                  className={`w-full p-2.5 pr-8 rounded-xl border-2 text-[11px] font-bold transition-all text-left h-12 flex flex-col justify-center ${
                    isSelected ? 'bg-orange-500/10 border-orange-500 text-white' : 'bg-slate-900/50 border-slate-800 text-slate-500'
                  }`}
                >
                  <span className="truncate w-full">{cat.name}</span>
                  {isSelected && <span className="text-[7px] opacity-60 uppercase">{wordOverrides[cat.id]?.length ?? cat.words.length} Words</span>}
                </button>
                {isSelected && (
                  <button onClick={(e) => { e.stopPropagation(); enterWordPicking(cat.id); }} className="absolute right-1 top-1/2 -translate-y-1/2 w-6 h-6 rounded-lg bg-orange-500/20 text-[10px] flex items-center justify-center transition-all z-10">⚙️</button>
                )}
                {hasOverrides && isSelected && <div className="absolute top-1 left-1 w-1 h-1 bg-orange-500 rounded-full"></div>}
              </div>
            );
          })}
        </div>
      </div>

      {/* Custom Words - Drastically Shrink to Fit */}
      <div className="bg-gradient-to-br from-indigo-900/20 to-violet-900/20 p-4 rounded-[2rem] border border-indigo-500/20 backdrop-blur-xl shadow-lg">
        <div className="flex justify-between items-center mb-2">
          <p className="text-[9px] font-black uppercase text-indigo-400">Custom Words</p>
          <button onClick={() => setGameState(GameState.MANAGE_CUSTOM)} className="text-[8px] font-black uppercase text-violet-400">Edit Data →</button>
        </div>
        <div className="flex gap-2">
          <textarea
            value={customWordsInput}
            onChange={(e) => setCustomWordsInput(e.target.value)}
            placeholder="Word, word, word..."
            className="flex-1 bg-slate-950/60 border border-slate-800/80 rounded-xl p-2.5 text-[10px] font-medium outline-none text-slate-100 placeholder:text-slate-700 min-h-[44px] max-h-[44px] resize-none"
          />
          <button onClick={handleAddCustomWords} className="px-3 bg-indigo-600 rounded-xl text-[8px] font-black text-white uppercase active:scale-95">Add</button>
        </div>
      </div>

      {/* Chaos Mode - Minimal */}
      <div className={`p-3.5 rounded-2xl border transition-all flex items-center justify-between cursor-pointer ${isChaosMode ? 'bg-red-950/20 border-red-500/50' : 'bg-slate-800/40 border-slate-700/50'}`} onClick={() => setIsChaosMode(!isChaosMode)}>
        <span className={`text-[9px] font-black uppercase ${isChaosMode ? 'text-red-400' : 'text-slate-500'}`}>Chaos Mode (2%)</span>
        <div className={`w-10 h-5 rounded-full relative border ${isChaosMode ? 'bg-red-600 border-red-400' : 'bg-slate-900 border-slate-700'}`}>
          <div className={`absolute top-0.5 bottom-0.5 w-4 rounded-full transition-all ${isChaosMode ? 'right-0.5 bg-white' : 'left-0.5 bg-slate-600'}`} />
        </div>
      </div>

      <button onClick={startGame} className="w-full py-4.5 rounded-[1.8rem] bg-gradient-to-r from-red-600 to-orange-500 text-white font-black text-xl active:scale-95 shadow-xl border-t border-white/10">START GAME</button>
    </div>
  );

  const renderPreReveal = () => (
    <div className="max-w-md mx-auto text-center space-y-6 animate-in fade-in zoom-in-95 mt-4">
      <div className="space-y-2">
        <p className="text-slate-500 uppercase tracking-widest text-[9px] font-black">Pass the phone to</p>
        <h2 className="text-5xl font-black text-white tracking-tighter">{players[currentPlayerIndex].name}</h2>
      </div>
      <div className="relative p-10 bg-slate-800/20 rounded-full border-2 border-dashed border-slate-700/50 w-fit mx-auto">
        <span className="text-6xl block animate-bounce">📱</span>
      </div>
      <button onClick={() => setGameState(GameState.REVEALING)} className="w-full py-5 rounded-[2rem] bg-white text-slate-950 font-black text-xl">I AM READY</button>
    </div>
  );

  const renderRevealing = () => (
    <div className="max-w-md mx-auto text-center space-y-6 animate-in fade-in mt-4">
      <div className="space-y-1">
        <h3 className="text-orange-500 font-black uppercase text-[9px] tracking-widest">{players[currentPlayerIndex].name}</h3>
        <p className="text-slate-500 text-[10px] font-bold uppercase">Tap to reveal</p>
      </div>
      <div onClick={() => setIsWordVisible(!isWordVisible)} className={`relative h-[20rem] rounded-[2.5rem] cursor-pointer transition-all flex items-center justify-center overflow-hidden border-2 ${isWordVisible ? 'bg-white border-white' : 'bg-slate-900 border-slate-800 shadow-xl'}`}>
        {isWordVisible ? (
          <div className="text-center p-6 animate-in zoom-in-90 duration-300">
            <p className="text-[8px] font-black uppercase tracking-[0.4em] text-slate-400 mb-4 opacity-60">Secret Assignment</p>
            <span className={`text-4xl font-black leading-tight ${players[currentPlayerIndex].isImposter ? 'text-red-600' : 'text-slate-950'}`}>{players[currentPlayerIndex].word}</span>
          </div>
        ) : (
          <div className="text-center opacity-20"><div className="text-8xl mb-4">🕵️</div><p className="font-black text-xs uppercase">Hold</p></div>
        )}
      </div>
      {isWordVisible && (
        <button onClick={() => {
          if (currentPlayerIndex < playerCount - 1) {
            setCurrentPlayerIndex(prev => prev + 1);
            setGameState(GameState.PRE_REVEAL);
            setIsWordVisible(false);
          } else {
            setGameState(GameState.DISCUSSION);
          }
        }} className="w-full py-5 rounded-[2rem] bg-orange-600 text-white font-black text-lg">I'VE SEEN IT</button>
      )}
    </div>
  );

  const renderDiscussion = () => (
    <div className="max-w-md mx-auto text-center space-y-6 animate-in fade-in zoom-in-95 mt-4 px-2">
      <div className="space-y-2">
        <h2 className="text-4xl font-black text-white tracking-tighter">DISCUSSION</h2>
        <p className="text-slate-500 text-[10px] font-bold uppercase tracking-wide">Find the spy before they figure out the word.</p>
      </div>
      <div className="grid grid-cols-2 gap-2">
        {players.map(p => (
          <div key={p.id} className="p-4 bg-slate-900/60 rounded-2xl border border-slate-800/80 text-slate-400 font-black text-xs">
            <span className="text-[8px] block opacity-40 uppercase mb-0.5">Agent {p.id}</span>{p.name}
          </div>
        ))}
      </div>
      <button onClick={() => setGameState(GameState.SETUP)} className="w-full py-4 rounded-2xl bg-slate-800/50 text-slate-400 font-black text-[10px] uppercase tracking-widest border border-slate-700/50">FINISH GAME</button>
    </div>
  );

  return (
    <div className="min-h-screen relative overflow-x-hidden pb-4">
      <div className="max-w-md mx-auto relative z-20 px-4">
        <Header />
        <main>
          {gameState === GameState.SETUP && renderSetup()}
          {gameState === GameState.PRE_REVEAL && renderPreReveal()}
          {gameState === GameState.REVEALING && renderRevealing()}
          {gameState === GameState.DISCUSSION && renderDiscussion()}
          {gameState === GameState.MANAGE_CUSTOM && renderManageCustom()}
          {gameState === GameState.PICK_WORDS && renderPickWords()}
        </main>
      </div>
      <div className="fixed inset-0 -z-10 pointer-events-none">
        <div className="absolute top-0 -left-20 w-[300px] h-[300px] bg-red-600/5 rounded-full blur-[80px]"></div>
        <div className="absolute bottom-0 -right-20 w-[300px] h-[300px] bg-orange-600/5 rounded-full blur-[80px]"></div>
      </div>
    </div>
  );
};

export default App;

